window.TERM_CARDS = [
  /* ================= 第1回（2026/4/15）細胞の構造と機能・細胞小器官 =================
     ※第7回と同じ短い形式に作り直し（1カード1論点・数行・\n で改行、表＝問い／裏＝図）。 */
  { id:"l1-01", src:"第1回 細胞・小器官", field:"生体分子", backImageOnly:true, term:"人体を構成する4大元素は？", desc:"O（酸素）約63%\nC（炭素）約20%\nH（水素）約10%\nN（窒素）約3%\n※酸素が最も多い。以下Ca・P…と続く。", image:"images/sl1_elements.webp", imageAlt:"体重70kgあたりの元素存在量の表" },
  { id:"l1-02", src:"第1回 細胞・小器官", field:"生体分子", backImageOnly:true, term:"生体を構成する主要な4種類の分子と、対応する代表的疾患は？", desc:"核酸 → がん\nタンパク質 → 尿毒症\n脂質 → 動脈硬化\n糖質 → 糖尿病", image:"images/sl1_molecules_disease.webp", imageAlt:"生化学で扱う4分子と医療で扱う疾患の対応" },
  { id:"l1-03", src:"第1回 細胞・小器官", field:"生体分子", backImageOnly:true, term:"生体内の主な官能基は？", desc:"ヒドロキシ基(-OH)・アミノ基(-NH₂)\nカルボキシ基(-COOH)・カルボニル基(C=O)\nメルカプト基/チオール基(-SH)・アルデヒド基(-CHO)\nアミド結合・エステル結合・リン酸エステル など", image:"images/sl1_functional_groups.webp", imageAlt:"生体内の主な官能基の表" },
  { id:"l1-04", src:"第1回 細胞・小器官", field:"代謝・酵素", backImageOnly:true, term:"代謝／同化／異化とは？", desc:"代謝＝生体内の物質の化学変化・外界との物質交換。\n同化＝エネルギーを使い複雑な物質を合成する（例：タンパク質合成）。\n異化＝物質を分解し、その過程でエネルギー(ATP)を獲得する。", image:"images/sl1_metabolism.webp", imageAlt:"同化・異化とエネルギー代謝の模式図" },
  { id:"l1-05", src:"第1回 細胞・小器官", field:"代謝・酵素", backImageOnly:true, term:"酵素の働きは？（活性化エネルギー）", desc:"酵素は反応の活性化エネルギーを下げ、反応を進みやすくする。\nE+S ⇄ ES → E+P と進む。\n酵素自身は反応の前後で変化しない（触媒）。", image:"images/sl1_enzyme_energy.webp", imageAlt:"酵素反応のエネルギー変化のグラフ" },
  { id:"l1-06", src:"第1回 細胞・小器官", field:"細胞", term:"生命（細胞）の3つの条件は？", desc:"①外界と区別された存在（細胞膜で仕切られる）\n②代謝によりエネルギー(ATP)を産生する\n③自己複製できる" },
  { id:"l1-07", src:"第1回 細胞・小器官", field:"細胞", backImageOnly:true, term:"成人の細胞数・種類と、真核細胞と原核細胞の違いは？", desc:"成人：約37兆個・約200種類の細胞に分化。\n真核細胞＝核膜に包まれた核とオルガネラをもつ（動物細胞）。\n原核細胞＝核膜がなくDNAは細胞質に、オルガネラをもたない（細菌）。", image:"images/sl1_cell_overview.webp", imageAlt:"真核細胞と原核細胞の模式図" },
  { id:"l1-08", src:"第1回 細胞・小器官", field:"核", backImageOnly:true, term:"核（Nucleus）の機能・構成と、分裂期の変化は？", desc:"遺伝情報（染色体）を収めるオルガネラ。DNA＋ヒストン(タンパク質)で構成。\n核小体・核膜・核膜孔・染色質からなる。\n分裂期には核膜が消失し、染色質が凝集して染色体になる。", image:"images/sl1_nucleus.webp", imageAlt:"通常の核と分裂期の核" },
  { id:"l1-09", src:"第1回 細胞・小器官", field:"小胞体・ゴルジ", backImageOnly:true, term:"小胞体(ER)とゴルジ体の機能は？", desc:"小胞体＝タンパク質合成の場（粗面ERにリボソームが結合）。\nゴルジ体＝糖修飾などの修飾・選別を行い輸送する。\nシス面→トランス面へと進む。", image:"images/sl1_er_golgi.webp", imageAlt:"小胞体とゴルジ体の機能" },
  { id:"l1-10", src:"第1回 細胞・小器官", field:"小胞体・ゴルジ", term:"ER（小胞体）ストレスとは？関連疾患は？", desc:"折りたたみ不良の異常タンパク質が小胞体に蓄積した状態。\nがんや神経変性疾患などに関連する。" },
  { id:"l1-11", src:"第1回 細胞・小器官", field:"リソソーム", backImageOnly:true, term:"リソソームの機能と、物質の取り込み経路は？", desc:"内部はpH約5の酸性で分解酵素をもち、物質を分解する（異化）。\nエンドサイトーシス：ピノサイトーシス(小さな物質)／ファゴサイトーシス(細菌など大きな物体)。\nオートファジー：古いオルガネラ等を包む。\nいずれもリソソームと融合して分解。", image:"images/sl1_lysosome.webp", imageAlt:"エンドサイトーシス・ファゴサイトーシス・オートファジー" },
  { id:"l1-12", src:"第1回 細胞・小器官", field:"リソソーム", term:"オートファジーとは？", desc:"古くなった細胞小器官などをオートファゴソームに包み込み、\nリソソームと融合して分解・再利用する仕組み。\nがん・神経変性疾患にも関連する。" },
  { id:"l1-13", src:"第1回 細胞・小器官", field:"ペルオキシソーム", term:"ペルオキシソームの機能は？", desc:"超長鎖（超極長）脂肪酸の分解（異化）を行う。\n有害なH₂O₂（過酸化水素）を分解するカタラーゼをもち無毒化する。" },
  { id:"l1-14", src:"第1回 細胞・小器官", field:"ミトコンドリア", backImageOnly:true, term:"ミトコンドリアの機能と構造は？", desc:"酸素を使ってATPを産生する（異化）。TCA回路・β酸化・電子伝達系の場。\n外膜・内膜（ひだ状のクリステ）・膜間腔・マトリックス。\n電子伝達系がH⁺を膜間腔へ汲み出し、その勾配でATP合成酵素がATPを産生。\n独自のミトコンドリアDNAをもつ。", image:"images/sl1_mitochondria.webp", imageAlt:"ミトコンドリアの構造とプロトンポンプ・ATP合成酵素" },
  { id:"l1-15", src:"第1回 細胞・小器官", field:"細胞質ゾル", term:"細胞質ゾル(Cytosol)にある代謝系は？", desc:"解糖系の酵素が存在する。\nグルコース→ピルビン酸に分解する（異化）。" },
  { id:"l1-16", src:"第1回 細胞・小器官", field:"まとめ", backImageOnly:true, term:"各オルガネラと代謝の対応は？（まとめ）", desc:"細胞質：解糖系でグルコース→ピルビン酸（異化）。\nミトコンドリア＋ペルオキシソーム：脂肪酸→アセチルCoA（異化）。\nミトコンドリア：TCA・電子伝達系でATP産生（異化）。\n小胞体：ATPを使いタンパク質合成（同化）。細胞膜：ATPで膜輸送。", image:"images/sl1_organelle_metabolism.webp", imageAlt:"細胞の各オルガネラと代謝のまとめ" },
  { id:"l1-17", src:"第1回 細胞・小器官", field:"組織", backImageOnly:true, term:"生体の階層構造は？（器官系→…→細胞）", desc:"器官系（例：骨格系）→器官（骨）→組織（骨組織）→細胞（骨細胞）。\n組織は細胞と細胞由来物質で構成される。\n組織の種類：上皮組織・結合組織・筋組織・神経組織。", image:"images/sl1_hierarchy.webp", imageAlt:"骨を例にした器官系→器官→組織→細胞の階層" },
  { id:"l1-18", src:"第1回 細胞・小器官", field:"組織", backImageOnly:true, term:"結合組織を構成する細胞と細胞由来物質は？", desc:"細胞：線維芽細胞・マクロファージ・肥満細胞など。\n細胞由来物質：コラーゲン線維(タンパク質)、\nプロテオグリカン(タンパク質＋糖質)、エラスチン(タンパク質)。", image:"images/sl1_connective_tissue.webp", imageAlt:"結合組織を構成する細胞と細胞由来物質" },

  /* ================= 第2回（2026/4/22）生体膜の構造と機能・細胞接着 =================
     ※第7回と同じ短い形式に作り直し（1カード1論点・数行・\n で改行、表＝問い／裏＝図）。 */
  { id:"l2-01", src:"第2回 生体膜・接着", field:"膜の化学", term:"親水性・疎水性・両親媒性とは？", desc:"親水性＝水に溶けやすい（極性が高い分子）。\n疎水性＝水に溶けにくい（無極性・電荷を帯びない）。\n両親媒性＝1分子内に親水性部分と疎水性部分をもつ。\n中性脂肪は全体が疎水性、リン脂質は両親媒性（界面活性物質）。" },
  { id:"l2-02", src:"第2回 生体膜・接着", field:"生体膜", backImageOnly:true, term:"細胞膜（生体膜）の基本構造は？", desc:"リン脂質二重層。\n親水性のリン酸基（頭部）が外側を向く。\n疎水性の脂肪酸（尾部）が内側で向かい合う。", image:"images/sl2_membrane_basic.webp", imageAlt:"生体膜の基本構造（リン脂質二重層）" },
  { id:"l2-03", src:"第2回 生体膜・接着", field:"生体膜", backImageOnly:true, term:"流動モザイクモデルとは？", desc:"脂質分子や膜タンパク質が膜平面内を側方へ自由に移動できるモデル（Singer & Nicolson）。\n回転・側方移動は容易。\n内在性タンパク質が反転（横断）することはまれ。", image:"images/sl2_fluid_mosaic.webp", imageAlt:"生体膜の流動モザイクモデル" },
  { id:"l2-04", src:"第2回 生体膜・接着", field:"生体膜", term:"膜の流動性の調節と、フリップフロップとは？", desc:"不飽和脂肪酸が多い→固まりにくく流動性を保つ（低温で多く合成）。\n飽和脂肪酸が多い→準結晶（固体）状態になりやすい（高温で多く合成）。\nフリップフロップ＝脂質が二重層の片側→反対側へ移る動き。酵素が関与し非常にまれ。" },
  { id:"l2-05", src:"第2回 生体膜・接着", field:"生体膜", backImageOnly:true, term:"細胞膜のリン脂質は内側と外側で何が違う？", desc:"内側（細胞質側）：ホスファチジルセリン(PS)・ホスファチジルエタノールアミン(PE)。\n外側：ホスファチジルコリン(PC)・スフィンゴミエリン(SM)。\n内外で組成が非対称。", image:"images/sl2_asymmetry.webp", imageAlt:"赤血球膜リン脂質の内外非対称分布" },
  { id:"l2-06", src:"第2回 生体膜・接着", field:"生体膜", backImageOnly:true, term:"赤血球膜のスペクトリンの役割は？", desc:"細胞骨格タンパク質で、膜の内側にネットワークを形成。\nアンキリンを介して膜タンパク質（陰イオン交換体など）を繋ぎとめる。\n膜タンパク質が勝手に拡散せず、赤血球の形が崩れないようにする。", image:"images/sl2_spectrin.webp", imageAlt:"スペクトリン・アンキリンによる赤血球膜の裏打ち構造" },
  { id:"l2-07", src:"第2回 生体膜・接着", field:"膜タンパク質", backImageOnly:true, term:"細胞膜の成分割合と、膜内在性タンパク質の膜貫通構造は？", desc:"成分：タンパク質50〜75%・脂質25〜50%・糖質10%程度。\n膜貫通部＝αヘリックス（約20〜25残基の疎水性アミノ酸で〜3nmを横切る）。\nタイプI/IIは1本（向きが逆）、IIIは複数、IVは複数鎖が集まりチャネルを形成。", image:"images/sl2_integral_types.webp", imageAlt:"膜内在性タンパク質の存在様式（タイプI〜IV）" },
  { id:"l2-08", src:"第2回 生体膜・接着", field:"膜タンパク質", backImageOnly:true, term:"脂質係留性膜タンパク質の4様式は？", desc:"①C末Cysにパルミトイル基（アシル化）\n②N末Glyにミリストイル基（アシル化）\n③C末Cysにファルネシル基（プレニル化・チオエステル結合）\n④C末のGPIアンカー", image:"images/sl2_lipid_anchored.webp", imageAlt:"脂質係留性膜タンパク質（アシル化・プレニル化・GPIアンカー）" },
  { id:"l2-09", src:"第2回 生体膜・接着", field:"膜タンパク質", backImageOnly:true, term:"膜タンパク質の糖鎖付加は、向きの何を示す？", desc:"糖鎖付加あり＝細胞外側。\n糖鎖付加なし＝細胞内側。\n糖鎖の有無で膜タンパク質の内外の向きがわかる（例：グリコホリン）。", image:"images/sl2_glycophorin.webp", imageAlt:"赤血球膜グリコホリンの糖鎖と配置（図10-8）" },
  { id:"l2-10", src:"第2回 生体膜・接着", field:"膜輸送", backImageOnly:true, term:"受動輸送と能動輸送の違いは？単純拡散で通れる物質は？", desc:"受動輸送＝エネルギー不要。単純拡散（濃度勾配に従う）と促進拡散（チャネル/輸送体）。\n能動輸送＝ポンプが関与しATPが必要、濃度勾配に逆らう。\n単純拡散で通れる：H₂O・O₂・N₂・CH₄など小さく無極性の分子。", image:"images/sl2_transport_passive_active.webp", imageAlt:"生体膜の透過性（受動輸送・能動輸送）" },
  { id:"l2-11", src:"第2回 生体膜・接着", field:"膜輸送", backImageOnly:true, term:"一次性能動輸送と二次性能動輸送の違いは？", desc:"一次性：ATP・光・基質酸化のエネルギーを直接使う（例：Na⁺/K⁺-ATPase）。\n二次性：イオンの濃度勾配を利用する（例：小腸のNa⁺駆動のアミノ酸・糖輸送）。\nイオンチャネルは電気化学ポテンシャルに従い、直接はエネルギーを使わない。", image:"images/sl2_transport_table.webp", imageAlt:"輸送の種類のまとめ表（表10-4）" },
  { id:"l2-12", src:"第2回 生体膜・接着", field:"膜輸送", term:"なぜ膜タンパク質は受動輸送（促進拡散）を促進できる？", desc:"極性・電荷のある溶質が疎水的な二重層の中央を通るには高い活性化エネルギーが必要。\n輸送担体が水素結合で溶質と相互作用し、親水性の通路を作る。\n活性化エネルギーを下げ、下り坂拡散を促進する。" },
  { id:"l2-13", src:"第2回 生体膜・接着", field:"膜輸送", term:"赤血球のグルコース輸送（グルコース・パーミアーゼ）の特徴は？", desc:"受動輸送（促進拡散）の典型例。\n輸送速度は外側グルコース濃度に依存し、飽和する（Kt・Vmax）。\n酵素反応（ミカエリス・メンテン式）に類似したキネティクス。" },
  { id:"l2-14", src:"第2回 生体膜・接着", field:"膜輸送", backImageOnly:true, term:"輸送体による共輸送と逆輸送の違いは？Cl⁻/HCO₃⁻交換体は？", desc:"単一輸送＝1種類の基質のみ。\n共輸送（同方向）＝2つの基質が同じ方向に動く。\n逆輸送（対向）＝2つの基質が逆方向に動く。\nCl⁻/HCO₃⁻交換体＝逆輸送の例。血液のCO₂運搬能を高める。", image:"images/sl2_transporter_types.webp", imageAlt:"膜内在性輸送タンパク質の分類（単一・共・逆輸送）" },
  { id:"l2-15", src:"第2回 生体膜・接着", field:"膜輸送", backImageOnly:true, term:"受容体依存性エンドサイトーシス（LDL・トランスフェリン）の流れは？", desc:"受容体に結合したLDLや鉄結合トランスフェリンが、クラスリン被覆小胞として取り込まれる。\n被覆がとれエンドソームと融合、低pH（pH6以下）で鉄・LDLが解離。\n受容体はアポトランスフェリンとともに細胞膜へ戻り再利用される。", image:"images/sl2_endocytosis.webp", imageAlt:"LDLとトランスフェリンの受容体依存性エンドサイトーシス" },
  { id:"l2-16", src:"第2回 生体膜・接着", field:"生体膜", term:"膜融合におけるアネキシンと融合タンパク質の役割は？", desc:"アネキシンが2つの膜を安定に近接させ並ばせる。\n融合タンパク質は膜貫通領域を一方の膜、融合ペプチドをもう一方の膜に挿入。\n連続性を失うことなく2つの膜を融合させる。" },
  { id:"l2-17", src:"第2回 生体膜・接着", field:"ECM", backImageOnly:true, term:"細胞外マトリックス（ECM）の成分と役割は？", desc:"細胞と細胞の間を満たす物質。\n成分：プロテオグリカン、線維状タンパク質（コラーゲン・エラスチン）、接着性糖タンパク質（フィブロネクチン・ラミニン）。\n外力への抵抗力・弾性を与える。結合組織で豊富、上皮では基底膜としてわずか。", image:"images/sl2_ecm.webp", imageAlt:"軟骨組織のプロテオグリカン（図3-17）" },
  { id:"l2-18", src:"第2回 生体膜・接着", field:"細胞接着", term:"細胞接着分子の4つのファミリーは？共通の構造は？", desc:"①インテグリン ②カドヘリン ③免疫グロブリン・スーパーファミリー ④セレクチン。\n※CD44はどれにも属さない。\nいずれも細胞外領域と細胞質領域をもつ膜貫通タンパク質。" },
  { id:"l2-19", src:"第2回 生体膜・接着", field:"細胞接着", backImageOnly:true, term:"インテグリンの構造と結合様式は？", desc:"α鎖とβ鎖のヘテロダイマー。\n細胞外でマトリックスタンパク質（フィブロネクチン等）とRGD配列を介して結合。\n細胞内はα-アクチニン・タリン等を介してアクチンフィラメントと会合。\n臓器・細胞ごとに異なる組み合わせが発現。", image:"images/sl2_integrin.webp", imageAlt:"インテグリン・ファミリーの構造" },
  { id:"l2-20", src:"第2回 生体膜・接着", field:"細胞接着", backImageOnly:true, term:"カドヘリンの結合に必要なイオンは？代表例は？", desc:"カルシウム（Ca²⁺）存在下で強固に結合（>1mMで強い接着）。\nCaがないとほどけ、Caが増えるとダイマー→強固な接着へ。\nE-カドヘリン＝上皮、N-カドヘリン＝神経・心筋。接着結合やデスモソームで機能。", image:"images/sl2_cadherin_ca.webp", imageAlt:"カドヘリンのCa²⁺依存的な結合" },
  { id:"l2-21", src:"第2回 生体膜・接着", field:"細胞接着", backImageOnly:true, term:"デスモソームの構成分子と連結する細胞骨格は？", desc:"膜タンパク質＝カドヘリン科のデスモグレイン(Dsg)・デスモコリン(Dsc)。\n細胞内成分＝プラコグロビン・デスモプラキン。\n中間径フィラメント（ケラチン）と連結する。", image:"images/sl2_desmosome.webp", imageAlt:"デスモソームの構成分子（Dsg・Dsc・デスモプラキン）" },
  { id:"l2-22", src:"第2回 生体膜・接着", field:"細胞接着", backImageOnly:true, term:"セレクチンの特徴と役割は？", desc:"C型（Ca²⁺依存性）レクチンで、糖鎖を認識して結合する。\nL-セレクチンは白血球（リンパ球）のローリングに関与。\n接着カスケードの最初（①ローリング→②停止→③安定接着）を担う。", image:"images/sl2_selectin.webp", imageAlt:"リンパ球接着カスケード（L-セレクチンによるローリング）" },
  { id:"l2-23", src:"第2回 生体膜・接着", field:"細胞接着", backImageOnly:true, term:"細胞接着装置の3分類と、上皮での並び順は？", desc:"閉鎖性結合＝密着結合（tight junction）。\n連結性結合＝接着結合・デスモソーム。\n交流性結合＝ギャップ結合。\n上皮では頂端側から密着結合→接着結合→ギャップ結合の順に並ぶ。", image:"images/sl2_junctions.webp", imageAlt:"細胞間の結合（密着結合・接着結合・ギャップ結合）" },
  { id:"l2-24", src:"第2回 生体膜・接着", field:"細胞接着", backImageOnly:true, term:"密着結合（tight junction）の機能と構成分子は？", desc:"細胞間隙を密閉し、分子やイオンの通過を防ぐ。\n膜の脂質やタンパク質の移動も制限する。\n構成分子＝クローディン(claudin)とオクルディン(occludin)。", image:"images/sl2_tight_junction_mol.webp", imageAlt:"密着結合の構成分子（claudin・occludin）" },
  { id:"l2-25", src:"第2回 生体膜・接着", field:"細胞接着", backImageOnly:true, term:"接着結合（adherens junction）でカドヘリンとアクチンを繋ぐものは？", desc:"カドヘリンが細胞外で結合。\n細胞内はα-カテニン・β-カテニン（とp120）を介してアクチンフィラメントに連結。\n細胞どうしを繋いで接着帯を形成する。", image:"images/sl2_catenin.webp", imageAlt:"カドヘリンとアクチンをつなぐα-・β-カテニン" },
  { id:"l2-26", src:"第2回 生体膜・接着", field:"細胞接着", backImageOnly:true, term:"ギャップ結合の構造と、通す物質は？", desc:"コネキシン6分子（6量体）が集まりコネクソン（半チャネル）を形成。\n隣接細胞のコネクソンと繋がって細胞間チャネルをつくる。\n分子量〜1000程度の低分子物質・イオンを直接通す（心筋などで重要）。", image:"images/sl2_gap_junction.webp", imageAlt:"ギャップ結合の構造（コネキシン・コネクソン）" },

  /* ================= 第3回（2026/5/13）ミネラル（無機質）の代謝 =================
     ※第7回と同じ短い形式に作り直し（1カード1論点・数行・\n で改行、表＝問い／裏＝図）。 */
  { id:"l3-01", src:"第3回 ミネラル", field:"ミネラル総論", backImageOnly:true, term:"ミネラル（無機質）とは？体重に占める割合は？", desc:"ミネラル＝生体を構成する元素のうち、O・C・H・N を除いた元素の総称。\nこのO・C・H・Nの4元素で体重の約96%。\nミネラルは残り約4%だけ。\n量は少ないが生理機能に必須。", image:"images/sl3_element_ratio.webp", imageAlt:"ヒトの体重に対する元素の含有割合（円グラフ）" },
  { id:"l3-02", src:"第3回 ミネラル", field:"ミネラル総論", backImageOnly:true, term:"多量ミネラルと微量ミネラルの違いは？体内に最も多いミネラルは？", desc:"多量ミネラル：体内10g以上・1日100mg以上（Ca・P・K・S・Na・Cl・Mg）。\n微量ミネラル：10g未満・100mg未満（Fe・Zn・Cu・I・Mn・Se・Mo・Cr・Co）。\n最も多いのはCa（約1000g）、次いでP（約700g）。", image:"images/sl3_mineral_amount.webp", imageAlt:"ミネラルの体内存在量の表（表18-2）" },
  { id:"l3-03", src:"第3回 ミネラル", field:"ミネラル総論", backImageOnly:true, term:"ミネラルの体内での2つの大きな役割は？", desc:"①生体組織の構成成分\n　骨・歯＝Ca・P・Mg、有機化合物（ヘム鉄など）＝P・Fe・I、酵素＝Mg・Zn・Cu・Mn・Mo・Se。\n②生体機能の調節\n　浸透圧・酸塩基平衡＝K・Na、筋収縮・神経伝達＝K・Na・Mg・Ca。", image:"images/sl3_mineral_roles.webp", imageAlt:"ミネラルの体内における役割の概略図" },
  { id:"l3-04", src:"第3回 ミネラル", field:"多量ミネラル", backImageOnly:true, term:"多量ミネラル（Ca・P・K・Na・Mg）の主な働きと欠乏症・過剰症は？", desc:"Ca・P：骨/歯の形成。欠乏でくる病・骨軟化症。\nK：細胞内、浸透圧維持。欠乏で低K血症／過剰で高K血症。\nNa：細胞外、浸透圧・血圧。過剰で高血圧症。\nMg：骨/歯・酵素の成分、細胞の興奮。", image:"images/sl3_macromineral_table.webp", imageAlt:"多量ミネラルの分布・生理作用・欠乏症の表（表1）" },
  { id:"l3-05", src:"第3回 ミネラル", field:"カルシウム", term:"カルシウム(Ca)の体内分布と血漿濃度は？", desc:"体内に最も多いミネラル。\n99%が骨・歯、1%が体液・軟組織に分布。\n血漿Ca濃度は約2.5mMに厳密に調節される。\n欠乏でくる病・骨軟化症・骨粗鬆症。" },
  { id:"l3-06", src:"第3回 ミネラル", field:"カルシウム", backImageOnly:true, term:"骨粗鬆症と骨軟化症の違いは？", desc:"骨粗鬆症：骨密度が全体的に低下（Ca：コラーゲン比は不変）。エストロゲン減少・運動不足など。\n骨軟化症：コラーゲンは正常でCaだけ低下（ビタミンD不足）。\n骨軟化症が小児（骨の伸長期）に起こると『くる病』。", image:"images/sl3_osteoporosis.webp", imageAlt:"骨粗鬆症と骨軟化症の概念図" },
  { id:"l3-07", src:"第3回 ミネラル", field:"カルシウム", backImageOnly:true, term:"細胞内カルシウムがシグナルとして働けるのはなぜ？その経路は？", desc:"細胞内Ca濃度は細胞外の約1万分の1と極めて低い→わずかな流入が大きな信号になる。\nホスホリパーゼCがPIP₂→IP₃＋DAG。\nIP₃が小胞体のCaチャネルを開きCa放出。\nCa＋DAGがPKCを活性化し基質をリン酸化。", image:"images/sl3_ca_signaling.webp", imageAlt:"IP3・DAG・PKCを介した細胞内カルシウムシグナル" },
  { id:"l3-08", src:"第3回 ミネラル", field:"カルシウム", backImageOnly:true, term:"ビタミンD₃の活性化の流れと、血中Caへの作用は？", desc:"プロビタミンD₃→〈皮膚・紫外線〉ビタミンD₃→〈肝臓〉25-OH体→〈腎臓〉活性型（1,25-(OH)₂D₃＝カルシトリオール）。\n活性型VitDは骨吸収・腎再吸収・腸管吸収を促し、血中Caを上げる。", image:"images/sl3_vitd_ca.webp", imageAlt:"ビタミンD3の代謝と血中カルシウム濃度の調節" },
  { id:"l3-09", src:"第3回 ミネラル", field:"カルシウム", backImageOnly:true, term:"血中カルシウムを調節する3つのホルモンの作用は？", desc:"副甲状腺ホルモン(PTH)：骨吸収↑・腎再吸収↑・活性型VitD産生↑→Ca上昇。\n活性型ビタミンD：腸吸収↑・腎再吸収↑→Ca上昇。\nカルシトニン：骨溶解↓・腎再吸収↓→Ca低下。", image:"images/sl3_ca_hormone_table.webp", imageAlt:"ホルモンによるカルシウム代謝調節の表" },
  { id:"l3-10", src:"第3回 ミネラル", field:"リン", backImageOnly:true, term:"リン(P)の体内分布と役割は？フッ素で歯が強くなるのはなぜ？", desc:"Caに次いで多いミネラル。\n85%はヒドロキシアパタイトとして骨・歯、14%が軟組織、1%が細胞内外・細胞膜。\n細胞内では核酸・リン脂質・ATPなどのリン酸化合物として働く。\nフッ素塗布でフルオロアパタイトに変わり耐酸性が上がる（虫歯予防）。", image:"images/sl3_apatite_fluoride.webp", imageAlt:"ヒドロキシアパタイトとフッ素（フルオロアパタイト・耐酸性向上）" },
  { id:"l3-11", src:"第3回 ミネラル", field:"カリウム・ナトリウム", backImageOnly:true, term:"カリウム(K)の分布と、濃度勾配をつくる仕組みは？", desc:"細胞内液の主要な陽イオン。\n98%が細胞内（約140mM）、2%が細胞外（約4mM）。\n細胞内外のK⁺勾配はNa⁺,K⁺-ATPアーゼが形成・維持。\nアルドステロンでK⁺の排出（尿中）が促進される。", image:"images/sl3_nak_distribution.webp", imageAlt:"細胞内外のナトリウム・カリウム濃度（図7）" },
  { id:"l3-12", src:"第3回 ミネラル", field:"カリウム・ナトリウム", term:"ナトリウム(Na)の分布と調節ホルモン・過剰症は？", desc:"細胞外液の主要な陽イオン。\n50%が細胞外（約145mM）、40%が骨、10%が細胞内。\nアルドステロンでNa⁺の再吸収が促進される。\n過剰症は高血圧症。" },
  { id:"l3-13", src:"第3回 ミネラル", field:"カリウム・ナトリウム", backImageOnly:true, term:"Na⁺,K⁺-ATPアーゼは1回で何を運ぶ？何を作る？", desc:"ATP 1分子の分解で、3分子のNa⁺を細胞外へ・2分子のK⁺を細胞内へ運ぶ。\n細胞内Naを低く・Kを高く保つ。\n濃度勾配と膜電位（細胞内が負）を形成する一次性能動輸送（P型ATPase）。", image:"images/sl3_nak_atpase.webp", imageAlt:"Na＋,K＋-ATPアーゼの作用機構モデル（3Na外・2K内）" },
  { id:"l3-14", src:"第3回 ミネラル", field:"イオン・膜輸送", backImageOnly:true, term:"細胞内外で濃度が大きく違う主なイオンは？（血漿 vs 細胞内, mM）", desc:"Na⁺：血漿145／細胞内12（外が高い）。\nK⁺：血漿4／細胞内139（内が高い）。\nCa²⁺：血漿1.8／細胞内<0.0002（細胞内は桁違いに低い）。\nNaは細胞外・Kは細胞内に多い。", image:"images/sl3_electrolyte_table.webp", imageAlt:"哺乳動物の細胞内外の電解質組成の表（表8-3）" },
  { id:"l3-15", src:"第3回 ミネラル", field:"カリウム・ナトリウム", backImageOnly:true, term:"レニン-アンジオテンシン-アルドステロン系の流れは？", desc:"腎臓からレニン分泌→アンジオテンシノーゲン(肝)→アンジオテンシンI→〈肺のACE〉→アンジオテンシンII→副腎皮質からアルドステロン→腎でNa⁺再吸収↑→血圧上昇。\n血圧とNa恒常性を担う中心経路。", image:"images/sl3_raa_system.webp", imageAlt:"レニン-アンジオテンシン-アルドステロン系のフローチャート" },
  { id:"l3-16", src:"第3回 ミネラル", field:"イオン・膜輸送", backImageOnly:true, term:"イオン輸送性ATPaseの3タイプ（P型・V型・F型）の違いは？", desc:"P型：形質膜。Na⁺K⁺-ATPase（膜電位）・H⁺K⁺-ATPase（胃の酸性化）・Ca²⁺-ATPase。\nV型：リソソーム・エンドソーム等でH⁺を汲み、内部pHを下げる（分解酵素を活性化）。\nF型：ミトコンドリア内膜で ADP+Pi→ATP を合成する（ATP合成酵素）。", image:"images/sl3_atpase_types.webp", imageAlt:"三つのタイプのイオン輸送性ATPase（P型・V型・F型）の表" },
  { id:"l3-17", src:"第3回 ミネラル", field:"イオン・膜輸送", term:"二次性能動輸送とは？共輸送と逆輸送の例は？", desc:"一次性能動輸送で作ったNa⁺やH⁺の濃度勾配を利用して、別の物質を勾配に逆らって運ぶ。\n共輸送（同方向）：腸・腎のブドウ糖-Na⁺、アミノ酸-Na⁺、大腸菌の乳糖-H⁺。\n逆輸送（対向）：Ca²⁺-Na⁺交換。" },
  { id:"l3-18", src:"第3回 ミネラル", field:"微量ミネラル", backImageOnly:true, term:"鉄(Fe)の吸収・運搬・貯蔵の流れは？", desc:"非ヘム鉄Fe³⁺はビタミンCでFe²⁺に還元され、十二指腸で吸収。\n血中で再びFe³⁺になり、トランスフェリン（輸送）が運びフェリチン（貯蔵）として肝臓などに蓄える。\nヘモグロビン・ミオグロビン合成に利用。\n赤血球寿命120日、脾臓で壊れた鉄はリサイクル。", image:"images/sl3_iron_transport.webp", imageAlt:"鉄の体内運搬（吸収・トランスフェリン・フェリチン・リサイクル）" },
  { id:"l3-19", src:"第3回 ミネラル", field:"微量ミネラル", backImageOnly:true, term:"鉄・亜鉛・銅の生理作用と欠乏症・過剰症は？", desc:"鉄：酸素運搬・ヘムの成分。欠乏で鉄欠乏性貧血／過剰でヘモクロマトーシス。\n亜鉛：SOD・DNAポリメラーゼの成分。欠乏で味覚障害。\n銅：セルロプラスミン・SODの成分。欠乏でメンケス病／過剰でウィルソン病。", image:"images/sl3_trace_minerals.webp", imageAlt:"微量ミネラルの体内分布・生理作用・欠乏症の表（鉄・亜鉛・銅）" },
  { id:"l3-20", src:"第3回 ミネラル", field:"微量ミネラル", backImageOnly:true, term:"マンガン・クロム・ヨウ素・モリブデン・セレンの働きと欠乏症は？", desc:"マンガン：SODなど酵素の成分→骨の発育障害。\nクロム：インスリン作用の増強→耐糖能の低下。\nヨウ素：甲状腺ホルモンの成分→甲状腺腫。\nモリブデン：酸化酵素の成分→成長障害。\nセレン：グルタチオンペルオキシダーゼの成分→克山病。", image:"images/sl3_trace_minerals.webp", imageAlt:"微量ミネラルの体内分布・生理作用・欠乏症の表（Mn・Cr・I・Mo・Se）" },

  /* ================= 第4回（2026/5/14）細胞骨格とモータータンパク質 =================
     ※第7回と同じ短い形式に作り直し（1カード1論点・数行・\n で改行）。情報量の多いスライドは分割して枚数を増やしてある。 */
  { id:"l4-01", src:"第4回 細胞骨格・モーター", field:"細胞骨格総論", term:"細胞骨格とモータータンパク質は、それぞれ何をする？", desc:"細胞骨格＝細胞の形をつくる骨組み。\nモータータンパク質＝細胞骨格と相互作用して動く。\nモーターの役割は2つ：\n①細胞の運動\n②細胞内での物質（小胞・オルガネラ）の輸送。" },
  { id:"l4-02", src:"第4回 細胞骨格・モーター", field:"筋収縮", backImageOnly:true, term:"筋肉が収縮する仕組みは？アクチンとミオシンの役割は？", desc:"アクチン（細い線維）とミオシン（太い線維）が互いに滑り込む＝滑り説。\n→サルコメアが短縮して筋収縮。\nこのときATPを大量に消費する。\n一般の細胞では アクチン＝細胞骨格、ミオシン＝モータータンパク質。", image:"images/sl4_sarcomere.webp", imageAlt:"サルコメアの構造と滑り説による筋収縮" },
  { id:"l4-03", src:"第4回 細胞骨格・モーター", field:"筋収縮", backImageOnly:true, term:"分子モーター・ミオシンの構造は？", desc:"2本のαヘリックスが巻き合った長い尾部（tail）＋2つの頭部（head）。\n頭部の付け根に軽鎖と首（ヒンジ）。\n頭部がATPを分解し、化学エネルギーを運動エネルギーに変換する。\n多数が束ねられ、中央は頭部のないbare zoneになる。", image:"images/sl4_myosin.webp", imageAlt:"ミオシン分子の構造（頭部・尾部・コイルドコイル）" },
  { id:"l4-04", src:"第4回 細胞骨格・モーター", field:"筋収縮", backImageOnly:true, term:"ミオシン頭部の首振り（クロスブリッジサイクル）はどう進む？ミオシンは何で活性化されるATPase？", desc:"①ATP結合→ミオシンがアクチンから外れる\n②ATP分解（ADP+Pi保持）で頭部が立つ\n③アクチンに再結合\n④Pi遊離→首振り（パワーストローク）でアクチンを引く\n⑤ADP遊離。\nミオシンはアクチンで活性化されるATPase。", image:"images/sl4_crossbridge.webp", imageAlt:"ミオシン頭部のクロスブリッジ（首振り）サイクル" },
  { id:"l4-05", src:"第4回 細胞骨格・モーター", field:"筋収縮", backImageOnly:true, term:"骨格筋が収縮・弛緩するときのCa²⁺の動きは？", desc:"脱分極がT管を伝わる→DHP受容体（電位依存性Ca²⁺チャネル）→筋小胞体のリアノジン受容体が開く→Ca²⁺が放出され収縮。\n弛緩：Ca²⁺-ATPase（ポンプ）がATPを使いCa²⁺を筋小胞体へ汲み戻す。", image:"images/sl4_ca_movement.webp", imageAlt:"筋収縮弛緩サイクルにおけるCa2+の動き（骨格筋・心筋）" },
  { id:"l4-06", src:"第4回 細胞骨格・モーター", field:"筋収縮", backImageOnly:true, term:"心筋細胞でCa²⁺やNa⁺・K⁺を運ぶ主な輸送体は？ウアバインは何を阻害する？", desc:"Na⁺/Ca²⁺交換体：Na⁺勾配を使いCa²⁺を細胞外へ排出。\nNa⁺/K⁺-ATPase：ATPで3Na⁺排出・2K⁺取り込み、イオン勾配を維持。\nウアバイン（強心配糖体）はこのNa⁺/K⁺-ATPaseを阻害する。", image:"images/sl4_ca_movement.webp", imageAlt:"筋収縮弛緩サイクルにおけるCa2+の動き（骨格筋・心筋）" },
  { id:"l4-07", src:"第4回 細胞骨格・モーター", field:"細胞骨格総論", backImageOnly:true, term:"細胞骨格の3つの構成要素と、太さ・構成タンパク質は？", desc:"①AF＝ミクロ（アクチン）フィラメント：アクチン、約6〜7nm（最も細い）。\n②IF＝中間径フィラメント：ケラチンなど、約10nm。\n③MT＝微小管：チューブリン、約25nm（最も太い・中空の管）。\n太さは AF＜IF＜MT。", image:"images/sl4_cytoskeleton_elements.webp", imageAlt:"細胞骨格の3構成要素（AF・IF・MT）" },
  { id:"l4-08", src:"第4回 細胞骨格・モーター", field:"細胞骨格総論", backImageOnly:true, term:"蛍光染色で見た3種のフィラメントの分布の特徴は？", desc:"アクチン：束ねられてストレスファイバーを形成。\n微小管：中心（中心体）から放射状に広がる。\n中間径フィラメント：細胞質全体に網目状に広がる。\nそれぞれ特異抗体＋蛍光で染め分けられる。", image:"images/sl4_three_filaments.webp", imageAlt:"三種の細胞質フィラメントの蛍光像と電子顕微鏡像（図2-18）" },
  { id:"l4-09", src:"第4回 細胞骨格・モーター", field:"アクチン", backImageOnly:true, term:"アクチンフィラメントの形成と、束・網目をつくる架橋タンパク質は？", desc:"球状のG-アクチンがATP依存的に重合→細い（6〜7nm）アクチンフィラメント（F-アクチン）。\nフィラミン：2本を直角に交差結合し網目をつくる。\nフォドリン：交差連結して束（凝集物）にする。", image:"images/sl4_actin_polymer.webp", imageAlt:"アクチンの重合とフィラミン・フォドリンによる架橋（図2-19）" },
  { id:"l4-10", src:"第4回 細胞骨格・モーター", field:"アクチン", backImageOnly:true, term:"アクチンフィラメントのプラス端・マイナス端では何が起こる？", desc:"プラス端：重合（ATP-G-アクチンが付加する成長端）。\nマイナス端：脱重合（ADP-アクチンが外れる端）。\nATPキャップがあると伸長が促進される。\nこの重合・脱重合で細胞骨格の形が変わる。", image:"images/sl4_actin_regulation.webp", imageAlt:"アクチンの重合・脱重合（プラス端・マイナス端）" },
  { id:"l4-11", src:"第4回 細胞骨格・モーター", field:"アクチン", backImageOnly:true, term:"アクチンの重合を制御するタンパク質（チモシン・プロフィリン・ゲルゾリン・Rho）の働きは？", desc:"チモシン：G-アクチンに結合し重合を抑える。\nプロフィリン：ADP→ATP交換を促し重合を促進。\nゲルゾリン：フィラメントを切断し、プラス端にキャップ。\nRho（低分子G-タンパク質）：重合を制御して細胞骨格を操る。", image:"images/sl4_actin_regulation.webp", imageAlt:"アクチンの制御タンパク質（チモシン・プロフィリン・ゲルゾリン・Rho）" },
  { id:"l4-12", src:"第4回 細胞骨格・モーター", field:"アクチン", backImageOnly:true, term:"小腸微絨毛（刷子縁）の芯をつくる構造は？", desc:"中心を貫くアクチン束（F-アクチン）を、フィンブリンとビリンが束ねて硬い芯にする。\nミオシンIとカルモジュリンがアクチン束と細胞膜を側方で架橋。\n根元（終末網）はスペクトリンや中間径フィラメントで固定される。", image:"images/sl4_microvilli.webp", imageAlt:"小腸微絨毛の芯を作る微細（アクチン）フィラメント" },
  { id:"l4-13", src:"第4回 細胞骨格・モーター", field:"中間径フィラメント", backImageOnly:true, term:"中間径フィラメントは単量体からどう組み立てられる？", desc:"①単量体（約46nm）→2本が平行に並び二量体。\n②二量体2つが逆向き平行で四量体（極性が消える）。\n③四量体が縦に連なりプロトフィラメント。\n④対で結合し原線維→4本がねじれてロープ状の直径10nmになる。", image:"images/sl4_if_structure.webp", imageAlt:"中間径フィラメントの重合過程（二量体→四量体→原線維）" },
  { id:"l4-14", src:"第4回 細胞骨格・モーター", field:"疾患", backImageOnly:true, term:"ケラチン（中間径フィラメントの一種）の異常でおこる皮膚疾患3つは？", desc:"①単純性表皮水疱症(EBS)：ケラチン5・14の変異（基底層）、擦れて水疱。\n②水疱型先天性魚鱗癬様紅皮症(HE)：ケラチン1・10の変異、過剰角化。\n③水疱性手掌足底角化症(EPPK)：ケラチン9の変異、手掌・足底に限局。", image:"images/sl4_keratin_disease.webp", imageAlt:"ケラチン異常による皮膚疾患（EBS・HE・EPPK）" },
  { id:"l4-15", src:"第4回 細胞骨格・モーター", field:"疾患", backImageOnly:true, term:"筋ジストロフィー（Duchenne／Becker型）の原因タンパク質と、その働きは？", desc:"原因はジストロフィンの異常（細胞骨格系の異常）。\nジストロフィンは巨大な線維状タンパク質。\n細胞内のアクチンと、細胞膜の糖タンパク質複合体（DGC）→基底膜（ラミニン）を連結する。\n欠損で筋細胞膜が脆くなり、筋線維が壊れる。", image:"images/sl4_dystrophin.webp", imageAlt:"ジストロフィンと糖タンパク質複合体(DGC)の骨格筋での概要（図6-29）" },
  { id:"l4-16", src:"第4回 細胞骨格・モーター", field:"微小管", backImageOnly:true, term:"微小管の構造は？重合を止める薬は？", desc:"α-チューブリンとβ-チューブリンの二量体が重合し、直径約25nmの中空の管になる。\nコルヒチンは微小管の重合（会合）を阻害する。\n→有糸分裂を止めるのに使われる。", image:"images/sl4_microtubule.webp", imageAlt:"チューブリン二量体から形成される微小管とコルヒチン（図2-21）" },
  { id:"l4-17", src:"第4回 細胞骨格・モーター", field:"微小管", backImageOnly:true, term:"繊毛・鞭毛の軸糸の断面構造(9+2)と、運動を担うモーターは？", desc:"中心の1対（シングレット）微小管を、9本のダブレット微小管（A管＋B管）が取り囲む＝9+2構造。\nダブレット間はネキシンで連結、中心へ放射状スポーク。\n各ダブレットの外腕・内腕ダイニンが隣を滑らせ、屈曲運動を生む。", image:"images/sl4_axoneme.webp", imageAlt:"繊毛・鞭毛の軸糸の9+2構造とダイニン腕" },
  { id:"l4-18", src:"第4回 細胞骨格・モーター", field:"モーター", backImageOnly:true, term:"微小管モーター・キネシンの構造と、運ぶ向きは？", desc:"2つの頭部（微小管に結合）＋長い柄部＋尾部（軽鎖で小胞に結合）。\nATPを使い、微小管のプラス端方向（細胞中心→辺縁）へ小胞を運ぶ＝順行性。\nミオシンはアクチン上、キネシンは微小管をレールに動く。", image:"images/sl4_kinesin.webp", imageAlt:"モータータンパク質キネシンの構造と小胞輸送" },
  { id:"l4-19", src:"第4回 細胞骨格・モーター", field:"モーター", backImageOnly:true, term:"ミオシンI・ミオシンII・キネシン・細胞質ダイニンを、頭部数・レール・向きで比べると？", desc:"頭部数：ミオシンI＝1、他は2。\nレール：ミオシン類＝アクチン、キネシン・ダイニン＝微小管。\n尾部：ミオシンI＝細胞膜、ミオシンII＝互いに束、キネシン・ダイニン＝小胞。\n向き：ダイニンだけマイナス端、他はプラス端。", image:"images/sl4_motor_compare.webp", imageAlt:"モータータンパク質の比較表（ミオシンI/II・キネシン・ダイニン）" },
  { id:"l4-20", src:"第4回 細胞骨格・モーター", field:"モーター", backImageOnly:true, term:"微小管モータータンパク質は機能で3つに分類される。それぞれの代表と向きは？", desc:"①細胞質モーター：キネシン(＋)・細胞質ダイニン(−)＝小胞/小器官の輸送。\n②分裂モーター：キネシンBimC・MCAK・CENP-E等＝紡錘体・染色体・動原体を動かす。\n③軸糸モーター：外腕・内腕ダイニン(−)＝繊毛・鞭毛のダブレット微小管。", image:"images/sl4_mt_motor_table.webp", imageAlt:"微小管モータータンパク質の機能による分類（表20-2）" },
  { id:"l4-21", src:"第4回 細胞骨格・モーター", field:"神経軸索輸送", backImageOnly:true, term:"神経軸索での順行性／逆行性輸送は、それぞれどのモーターが担う？", desc:"軸索の微小管はプラス端が末端（シナプス）側を向く。\n順行性輸送（細胞体→シナプス、プラス端向き）＝キネシン。\n逆行性輸送（シナプス→細胞体、マイナス端向き）＝細胞質ダイニン。", image:"images/sl4_axon_bidirectional.webp", imageAlt:"軸索におけるオルガネラの両方向輸送（キネシン・細胞質ダイニン）" },
  { id:"l4-22", src:"第4回 細胞骨格・モーター", field:"神経軸索輸送", backImageOnly:true, term:"軸索輸送で、キネシンとダイニンはそれぞれどんな積み荷を運ぶ？", desc:"キネシン（プラス端＝順行）：分泌小胞・リソソーム・ミトコンドリアなどを末端へ。\n細胞質ダイニン（マイナス端＝逆行）：エンドソーム・色素顆粒などを細胞体側へ。\n中心のMTOC（微小管形成中心）が微小管のマイナス端。", image:"images/sl4_axonal_transport.webp", imageAlt:"神経軸索輸送における積み荷とモーター（キネシン・ダイニン）" },
  { id:"l4-23", src:"第4回 細胞骨格・モーター", field:"まとめ", backImageOnly:true, term:"各モータータンパク質が動く「向き」を整理せよ。例外はどれ？", desc:"アクチン上：ミオシンI・IIともにプラス端方向。\n微小管上：キネシン（多く）＝プラス端＝順行、ダイニン＝マイナス端＝逆行。\n「ほぼ全部プラス端向き、ダイニンだけマイナス端向き」と覚える（一部キネシンNcdは例外）。", image:"images/sl4_motor_compare.webp", imageAlt:"モータータンパク質が動く方向の比較" },

  /* ================= 第5回（2026/5/20）タンパク質の構造・アミノ酸・タンパク質代謝 =================
     ※第7回と同じ短い形式に作り直し（1カード1論点・数行・\n で改行）。情報量の多いスライドは分割して枚数を増やしてある。 */
  { id:"l5-01", src:"第5回 タンパク質・アミノ酸", field:"タンパク質総論", backImageOnly:true, term:"タンパク質は生理的機能でどう分類される？（7種）", desc:"①酵素タンパク質。\n②輸送タンパク質（ヘモグロビン・アルブミン・リポタンパク質）。\n③収縮タンパク質（アクチン・ミオシン・チューブリン）。\n④調節タンパク質（ペプチドホルモン・転写因子・受容体）。\n⑤防御タンパク質（免疫グロブリン・フィブリノーゲン）。\n⑥貯蔵タンパク質（フェリチン・カゼイン）。\n⑦構造タンパク質（コラーゲン・エラスチン・ケラチン）。", image:"images/sl5_protein_functions.webp", imageAlt:"タンパク質の生理的機能に基づく分類とその例（表4-1）" },
  { id:"l5-02", src:"第5回 タンパク質・アミノ酸", field:"アミノ酸", backImageOnly:true, term:"アミノ酸の基本構造は？L型・D型と例外は？", desc:"α炭素に、アミノ基・カルボキシ基・水素・側鎖(R)が結合。\nα炭素は不斉炭素→鏡像異性体（L型・D型）がある。\nヒトのタンパク質はL型（老化でD型が生じることも）。\n例外：グリシン（側鎖がHで不斉炭素なし）、プロリン（環状）。", image:"images/sl5_amino_acid_structure.webp", imageAlt:"α-アミノ酸の構造とL体・D体（図4-1）" },
  { id:"l5-03", src:"第5回 タンパク質・アミノ酸", field:"アミノ酸", backImageOnly:true, term:"アミノ酸の等電点(pI)とは？酸性・塩基性でどんなイオンになる？", desc:"アミノ酸は両性電解質（酸にも塩基にもなる）。\n等電点(pI)＝正味の電荷が0になるpH。\n酸性側（低pH）→陽イオン型。\n塩基性側（高pH）→陰イオン型。\npI＝(pK1＋pK2)/2（例：グリシンで約6.0）。", image:"images/sl5_titration.webp", imageAlt:"アミノ酸の滴定曲線と等電点（図2）" },
  { id:"l5-04", src:"第5回 タンパク質・アミノ酸", field:"アミノ酸", backImageOnly:true, term:"アミノ酸・タンパク質の呈色反応と、検出する側鎖・アミノ酸は？", desc:"ニンヒドリン反応＝アミノ基（Pro以外）→青紫。\nキサントプロテイン反応＝芳香環→黄。\n坂口反応＝グアニジノ基（アルギニン）→赤。\nミロン反応＝フェノール基（チロシン）→赤。\nエルマン反応＝チオール基（システイン）→黄。\nエールリッヒ反応＝インドール環（トリプトファン）→青紫。", image:"images/sl5_color_reactions.webp", imageAlt:"アミノ酸側鎖の呈色反応（表3）" },
  { id:"l5-05", src:"第5回 タンパク質・アミノ酸", field:"アミノ酸", backImageOnly:true, term:"20種アミノ酸の「化学的性質」による分類は？酸性・塩基性はどれ？", desc:"側鎖の性質で分類する。\n中性アミノ酸（多数：脂肪族・芳香族など）。\n酸性アミノ酸＝アスパラギン酸・グルタミン酸（pIが低い）。\n塩基性アミノ酸＝リシン・アルギニン・ヒスチジン（pIが高い）。\n略号は3文字／1文字で表記。", image:"images/sl5_amino_acid_table.webp", imageAlt:"20種のアミノ酸の分類・略号・等電点（表4-2）" },
  { id:"l5-06", src:"第5回 タンパク質・アミノ酸", field:"アミノ酸", backImageOnly:true, term:"アミノ酸の「構造」による分類（BCAA・AAA・含硫・ヒドロキシ）は？", desc:"分枝鎖アミノ酸(BCAA)＝バリン・ロイシン・イソロイシン。\n芳香族アミノ酸(AAA)＝トリプトファン・フェニルアラニン・チロシン。\nヒドロキシアミノ酸＝セリン・トレオニン・チロシン（リン酸化され得る）。\n含硫アミノ酸＝システイン・メチオニン。", image:"images/sl5_amino_acid_table.webp", imageAlt:"アミノ酸の分類（分枝・芳香族・含硫・ヒドロキシ）（表4-2）" },
  { id:"l5-07", src:"第5回 タンパク質・アミノ酸", field:"アミノ酸", backImageOnly:true, term:"必須アミノ酸は何種類・何？乳幼児で加わるのは？", desc:"体内で合成できず食事から摂る必要があるもの。\n成人9種：バリン・ロイシン・イソロイシン・トレオニン・メチオニン・リシン・フェニルアラニン・トリプトファン・ヒスチジン。\n乳幼児ではアルギニンが加わる。", image:"images/sl5_essential_aa.webp", imageAlt:"乳幼児と成人の必須アミノ酸（図7-4）" },
  { id:"l5-08", src:"第5回 タンパク質・アミノ酸", field:"アミノ酸", backImageOnly:true, term:"タンパク質を構成しないが代謝で重要なアミノ酸・中間体は？", desc:"シトルリン・オルニチン＝尿素回路の中間体。\nDOPA＝メラニン・カテコールアミンの中間体。\n5-アミノレブリン酸＝ヘム合成の中間体。\nホモシステイン＝メチオニン代謝の中間体。\nGABA＝抑制性神経伝達物質。\nβ-アラニン＝CoAの一部。", image:"images/sl5_nonprotein_aa.webp", imageAlt:"タンパク質構成以外のアミノ酸の例（図4-2）" },
  { id:"l5-09", src:"第5回 タンパク質・アミノ酸", field:"ペプチド", backImageOnly:true, term:"ペプチド結合とは？N末端・C末端・主鎖・側鎖・残基とは？", desc:"アミノ酸のカルボキシ基とアミノ基が脱水縮合した共有結合（アミド結合）。\nN末端＝遊離アミノ基の側、C末端＝遊離カルボキシ基の側。\n主鎖＝ペプチド結合の連なり、側鎖＝各アミノ酸に固有のR基。\n残基＝鎖に組み込まれた各アミノ酸。\n（2〜数個＝ジ/トリ、10〜50個＝ポリペプチド）", image:"images/sl5_peptide_bond.webp", imageAlt:"ペプチド結合とタンパク質の構成・各名称（図7-5）" },
  { id:"l5-10", src:"第5回 タンパク質・アミノ酸", field:"生理活性ペプチド", backImageOnly:true, term:"代表的な生理活性ペプチド①（血糖・水・Ca・食欲の調節）は？", desc:"インスリン(51)＝血糖を下げる（膵β細胞）。\nグルカゴン(29)＝血糖を上げる（膵α細胞）。\nバソプレシン(9)＝水の再吸収・血圧上昇（下垂体後葉）。\nカルシトニン(32)＝血中カルシウムを下げる（甲状腺）。\nレプチン(146)＝食欲抑制・代謝調節（脂肪細胞）。", image:"images/sl5_bioactive_peptides.webp", imageAlt:"代表的な生理活性ペプチド（表6）" },
  { id:"l5-11", src:"第5回 タンパク質・アミノ酸", field:"生理活性ペプチド", backImageOnly:true, term:"代表的な生理活性ペプチド②（消化管・その他）は？", desc:"ガストリン(17)＝胃酸分泌を促進。\nセクレチン(28)＝膵液分泌促進・ガストリン抑制。\nコレシストキニン(33)＝胆嚢収縮・膵酵素分泌。\nグルタチオン(3)＝抗酸化（SH基で還元状態を保つ）。\nエンドルフィン(31)＝モルヒネ様の鎮痛作用。", image:"images/sl5_bioactive_peptides.webp", imageAlt:"代表的な生理活性ペプチド（表6）" },
  { id:"l5-12", src:"第5回 タンパク質・アミノ酸", field:"タンパク質分類", backImageOnly:true, term:"単純タンパク質と複合タンパク質の違いと例は？", desc:"単純＝アミノ酸のみ。アルブミン・グロブリン・ヒストン・プロタミン・硬タンパク質（コラーゲン等）。\n複合＝アミノ酸＋非タンパク成分。\nリポタンパク質(＋脂質)、ヘムタンパク質(＋ヘム＝Hb・ミオグロビン)、糖タンパク質、金属タンパク質、核タンパク質。", image:"images/sl5_protein_types.webp", imageAlt:"単純タンパク質と複合タンパク質の例（表7）" },
  { id:"l5-13", src:"第5回 タンパク質・アミノ酸", field:"立体構造", backImageOnly:true, term:"タンパク質の高次構造（一次〜四次）の階層は？", desc:"一次構造＝アミノ酸配列（遺伝情報で決まる）。\n二次構造＝αヘリックス・βシート・ターン・ループ（部分的な立体構造）。\n三次構造＝1本の鎖全体の立体構造（ドメイン・モチーフを含む）。\n四次構造＝複数サブユニットが集まった複合体。", image:"images/sl5_structure_hierarchy.webp", imageAlt:"タンパク質の高次構造の階層（図7-6）" },
  { id:"l5-14", src:"第5回 タンパク質・アミノ酸", field:"立体構造", backImageOnly:true, term:"二次構造のαヘリックスとβシートの特徴は？何で安定化される？", desc:"主鎖どうしの水素結合で安定化される部分的な立体構造。\nαヘリックス＝らせん状（約3.6残基で1回転）。膜貫通部分に多い。\nβシート＝2本以上の鎖が並んでできる平面様の構造。\n（ほかにターン・ループがある）", image:"images/sl5_secondary.webp", imageAlt:"αヘリックスとβシート（図4-5）" },
  { id:"l5-15", src:"第5回 タンパク質・アミノ酸", field:"立体構造", backImageOnly:true, term:"タンパク質の立体構造を作る結合・相互作用は？", desc:"ペプチド結合・ジスルフィド(S-S)結合＝共有結合。\nイオン結合（＋と−の側鎖）。\n水素結合。\n疎水性相互作用（疎水性側鎖が内側に集まる）。\nファンデルワールス力。", image:"images/sl5_bonds.webp", imageAlt:"タンパク質の立体構造を形成する各種の結合（図4-7）" },
  { id:"l5-16", src:"第5回 タンパク質・アミノ酸", field:"立体構造", backImageOnly:true, term:"三次構造とは？ドメイン・モチーフとは？", desc:"1本のポリペプチド鎖全体が折りたたまれた立体構造。\n親水性の側鎖は外側、疎水性の側鎖は内側に埋め込まれる。\nドメイン＝構造的・機能的にまとまった領域（30〜300残基）。\nモチーフ＝ドメインより短い、特有の機能をもつ配列。", image:"images/sl5_tertiary_quaternary.webp", imageAlt:"タンパク質の三次構造と四次構造（図7-10）" },
  { id:"l5-17", src:"第5回 タンパク質・アミノ酸", field:"立体構造", backImageOnly:true, term:"四次構造とは？ヘモグロビンとミオグロビンで比較すると？", desc:"複数のサブユニット（三次構造の鎖）が集まった複合体。\nヘモグロビン＝α2個＋β2個の四量体。酸素4個と結合。\nミオグロビン＝単量体。酸素1個と結合し、筋肉で酸素を貯蔵。", image:"images/sl5_tertiary_quaternary.webp", imageAlt:"タンパク質の三次構造と四次構造（ヘモグロビン）（図7-10）" },
  { id:"l5-18", src:"第5回 タンパク質・アミノ酸", field:"立体構造・臨床", backImageOnly:true, term:"ヘモグロビンとミオグロビンの酸素解離曲線の違いは？", desc:"ミオグロビン＝酸素親和性が高く、双曲線型（低酸素でも飽和）。\nヘモグロビン＝サブユニット間の協同効果でS字型。\n→肺(高PO₂)で酸素を受け取り、末梢(低PO₂)で放出できる。\nCO₂・H⁺・体温↑で右方移動し放出しやすくなる（ボーア効果）。", image:"images/sl5_o2_curve.webp", imageAlt:"ヘモグロビンとミオグロビンの酸素解離曲線の違い（図）" },
  { id:"l5-19", src:"第5回 タンパク質・アミノ酸", field:"タンパク質消化", backImageOnly:true, term:"主なプロテアーゼの基質特異性は？エンド型とエキソ型の違いは？", desc:"エンドペプチダーゼ＝内部を切る：\nペプシン(芳香族)・トリプシン(塩基性のC側)・キモトリプシン(芳香族のC側)。\nエキソペプチダーゼ＝末端を切る：\nカルボキシペプチダーゼ(C末端)・アミノペプチダーゼ(N末端)・ジペプチダーゼ(ジペプチド)。", image:"images/sl5_protease.webp", imageAlt:"プロテアーゼの基質特異性（表1）" },
  { id:"l5-20", src:"第5回 タンパク質・アミノ酸", field:"アミノ酸代謝", backImageOnly:true, term:"糖原性アミノ酸とケト原性アミノ酸とは？ケト原性のみは？", desc:"アミノ酸の炭素骨格の行き先で分類。\n糖原性＝ピルビン酸やTCA中間体になり糖新生に使える（大多数）。\nケト原性＝アセチルCoA等になり脂肪酸・ケトン体に。\nケト原性のみ＝ロイシン・リシン。\n両方＝イソロイシン・フェニルアラニン・チロシン・トリプトファン・トレオニン。", image:"images/sl5_gluco_keto.webp", imageAlt:"アミノ酸の炭素骨格の代謝とクエン酸回路（図12-3）" },
  { id:"l5-21", src:"第5回 タンパク質・アミノ酸", field:"アミノ酸代謝・臨床", backImageOnly:true, term:"アミノ基転移反応と酸化的脱アミノ反応とは？AST・ALTの意味と補酵素は？", desc:"アミノ基転移＝アミノ基をα-ケトグルタル酸に渡し、グルタミン酸を作る。\n酸化的脱アミノ＝グルタミン酸デヒドロゲナーゼがアンモニアを遊離（尿素回路へ）。\n補酵素はPLP（ビタミンB₆）。\nAST・ALTは代表的な転移酵素で、肝障害で血中に上昇＝肝機能マーカー。", image:"images/sl5_transamination.webp", imageAlt:"アミノ基転移と酸化的脱アミノ反応、AST/ALT（図8-7・図2）" },
  { id:"l5-22", src:"第5回 タンパク質・アミノ酸", field:"エネルギー代謝", backImageOnly:true, term:"ピルビン酸デヒドロゲナーゼ(PDH)複合体の反応・5補酵素・関連するビタミン欠乏症は？", desc:"ピルビン酸→アセチルCoA（酸化的脱炭酸）を触媒。E₁・E₂・E₃からなる。\n5つの補酵素：TPP(B₁)・α-リポ酸・CoA(パントテン酸)・FAD(B₂)・NAD⁺(ナイアシン)。\nNAD⁺/CoAで促進、NADH/アセチルCoAで抑制。\nビタミンB₁欠乏→脚気・Wernicke脳症。", image:"images/sl5_pdh.webp", imageAlt:"ピルビン酸デヒドロゲナーゼ複合体の構成と補酵素・ビタミン" },
  { id:"l5-23", src:"第5回 タンパク質・アミノ酸", field:"エネルギー代謝", backImageOnly:true, term:"クエン酸回路の概要は？1アセチルCoAから何ができる？", desc:"アセチルCoA(C2)＋オキサロ酢酸(C4)→クエン酸(C6)から始まる8段階の回路（ミトコンドリア）。\n1アセチルCoAあたり：\n・NADH 3分子\n・FADH₂ 1分子\n・GTP 1分子\n・CO₂ 2分子\nNADH・FADH₂は電子伝達系でATPになる。", image:"images/sl5_tca_overview.webp", imageAlt:"クエン酸回路の概要（1アセチルCoAあたりの産物）" },
  { id:"l5-24", src:"第5回 タンパク質・アミノ酸", field:"エネルギー代謝", backImageOnly:true, term:"クエン酸回路の律速酵素3つは？アナプレロティック反応とは？", desc:"律速（調節）酵素は3つ：\n①クエン酸シンターゼ。\n②イソクエン酸デヒドロゲナーゼ（ADP/NAD⁺で促進、NADH/ATPで抑制）。\n③α-ケトグルタル酸デヒドロゲナーゼ（NADH・スクシニルCoAで抑制）。\nアナプレロティック反応＝生合成で消費された中間体を補充する反応（例：ピルビン酸→オキサロ酢酸）。", image:"images/sl5_tca_regulation.webp", imageAlt:"クエン酸回路の調節（律速酵素とアナプレロティック反応）（図4-12）" },

  /* ================= 第6回（2026/5/21）タンパク質代謝と調節（アミノ酸分解・尿素回路・電子伝達系） =================
     ※第7回と同じ短い形式に作り直し（1カード1論点・数行・\n で改行）。情報量の多いスライドは分割して枚数を増やしてある。 */
  { id:"l6-01", src:"第6回 アミノ酸代謝・尿素回路", field:"総論", backImageOnly:true, term:"アミノ酸（アミノ酸プール）の主な使い道は？", desc:"食事や体タンパク質の分解でできたアミノ酸が集まった溜まりが「アミノ酸プール」。\n使い道は主に3つ：\n①脱アミノ→炭素骨格をエネルギー・糖新生・脂肪酸に。\n②脱炭酸→生理活性アミンに。\n③体タンパク質などの窒素源に。\n外したアンモニアは尿素回路で無毒化。", image:"images/sl6_overview.webp", imageAlt:"タンパク質の分解とアミノ酸代謝の概略図" },
  { id:"l6-02", src:"第6回 アミノ酸代謝・尿素回路", field:"アミノ酸の分解", backImageOnly:true, term:"アミノ酸の分解はまず何から始まる？糖原性・ケト原性とは？", desc:"まず脱アミノ反応でアミノ基を外し、炭素骨格がα-ケト酸（2-オキソ酸）になる。\nα-ケト酸の行き先で分類：\n糖原性＝ピルビン酸やTCA中間体になり糖新生に使える（大多数）。\nケト原性＝アセチルCoA等になり脂肪酸・ケトン体に。\nロイシン・リシンはケト原性のみ。", image:"images/sl6_deamination.webp", imageAlt:"アミノ酸の脱アミノ反応によるα-ケト酸の産生（図8-5）" },
  { id:"l6-03", src:"第6回 アミノ酸代謝・尿素回路", field:"アミノ酸の分解", backImageOnly:true, term:"酸化的脱アミノ反応とは？アミノ基はどうなる？", desc:"グルタミン酸デヒドロゲナーゼ（やアミノ酸オキシダーゼ）がアミノ酸を酸化。\nアミノ基をアンモニア(NH₃)として遊離させる。\n多くのアミノ酸はまずアミノ基転移で窒素をグルタミン酸に集約→ここでまとめてNH₃を切り出す。\n遊離NH₃は有毒なので尿素回路へ。", image:"images/sl6_ox_deamination.webp", imageAlt:"アミノ酸オキシダーゼによる酸化的脱アミノ反応（図4）" },
  { id:"l6-04", src:"第6回 アミノ酸代謝・尿素回路", field:"アミノ酸の分解", backImageOnly:true, term:"グルコース-アラニン回路とは？筋肉と肝臓で何をやりとりする？", desc:"筋肉と肝臓がグルコースとアラニンで窒素とエネルギーを受け渡すサイクル。\n筋：アミノ基をピルビン酸に転移→アラニンにして肝へ（ALT、補酵素PLP）。\n肝：アラニン→ピルビン酸→糖新生でグルコース→筋へ戻す。\n→筋のアンモニアを安全に肝へ運び、尿素回路で処理。", image:"images/sl6_glucose_alanine.webp", imageAlt:"グルコース-アラニン回路（図8-8）" },
  { id:"l6-05", src:"第6回 アミノ酸代謝・尿素回路", field:"尿素回路", backImageOnly:true, term:"尿素回路（オルニチン回路）の役割・場所と、5つの酵素反応は？", desc:"有毒なアンモニアを無毒な尿素に変えて排泄（肝臓、ミトコンドリア＋細胞質）。\n①カルバモイルリン酸シンテターゼI（NH₃＋CO₂＋2ATP）\n②オルニチントランスカルバモイラーゼ→シトルリン\n③アルギニノコハク酸シンテターゼ（＋アスパラギン酸）\n④アルギニノコハク酸リアーゼ→アルギニン＋フマル酸\n⑤アルギナーゼ→尿素＋オルニチン（再利用）", image:"images/sl6_urea_cycle.webp", imageAlt:"尿素回路（オルニチン回路）（図12-2）" },
  { id:"l6-06", src:"第6回 アミノ酸代謝・尿素回路", field:"尿素回路", backImageOnly:true, term:"尿素の2つの窒素はどこから来る？尿素1分子でATPを何個使う？", desc:"尿素の窒素は2つ：\n①遊離アンモニア由来（カルバモイルリン酸経由）。\n②アスパラギン酸由来。\n最後にアルギナーゼがアルギニン→尿素＋オルニチン。\n尿素1分子の生成にATPを3分子消費する。", image:"images/sl6_arginase.webp", imageAlt:"アルギナーゼによる尿素生成と尿素の窒素の由来（図6）" },
  { id:"l6-07", src:"第6回 アミノ酸代謝・尿素回路", field:"尿素回路・臨床", term:"高アンモニア血症でなぜ神経障害（意識障害・痙攣）が起こる？", desc:"血中アンモニアが増えると、グルタミン酸デヒドロゲナーゼが逆反応に傾く。\nα-ケトグルタル酸＋NH₃→グルタミン酸。\n→TCA回路の中間体α-ケトグルタル酸が枯渇。\n→脳でTCA回路が回らずATP不足→意識障害・痙攣。" },
  { id:"l6-08", src:"第6回 アミノ酸代謝・尿素回路", field:"疾患（一覧）", backImageOnly:true, term:"アミノ酸代謝酵素の欠損で起こる先天性疾患（代謝異常症）7つと欠損酵素は？", desc:"フェニルケトン尿症＝フェニルアラニンヒドロキシラーゼ。\nアルカプトン尿症＝ホモゲンチジン酸オキシダーゼ。\nメープルシロップ尿症＝分枝α-ケト酸デヒドロゲナーゼ。\nホモシスチン尿症＝シスタチオニンβ-シンターゼ。\n白皮症＝チロシナーゼ。\n高チロシン血症＝チロシントランスアミナーゼ等。\nシトルリン血症＝アルギニノコハク酸シンターゼ（尿素回路）。", image:"images/sl6_aa_disorders.webp", imageAlt:"代表的なアミノ酸代謝酵素欠損症の一覧（表8-1）" },
  { id:"l6-09", src:"第6回 アミノ酸代謝・尿素回路", field:"疾患", backImageOnly:true, term:"フェニルケトン尿症の原因・症状・予防は？（Phe→Tyrの経路）", desc:"フェニルアラニンヒドロキシラーゼ（補酵素BH₄）がPhe→Tyrを触媒。\n欠損するとフェニルアラニンと代謝物が蓄積。\n→脳に障害、精神遅滞。\n予防：発達期に低フェニルアラニン食。", image:"images/sl6_phe_tyr_synthesis.webp", imageAlt:"フェニルアラニンからチロシンの生成（図12-5）" },
  { id:"l6-10", src:"第6回 アミノ酸代謝・尿素回路", field:"疾患", backImageOnly:true, term:"アルカプトン尿症の原因と特徴は？（チロシン分解の経路）", desc:"チロシン分解の途中で、ホモゲンチジン酸オキシダーゼが欠損。\nホモゲンチジン酸が蓄積する。\n特徴：尿が空気に触れると黒く変色。\n関節炎・黒色の色素沈着。", image:"images/sl6_phe_tyr_catabolism.webp", imageAlt:"フェニルアラニン・チロシンの代謝経路（図12-6）" },
  { id:"l6-11", src:"第6回 アミノ酸代謝・尿素回路", field:"疾患", backImageOnly:true, term:"メープルシロップ尿症の原因と特徴は？（分枝アミノ酸の分解）", desc:"分枝アミノ酸(バリン・ロイシン・イソロイシン)の分解で、分枝α-ケト酸デヒドロゲナーゼが欠損。\n分枝α-ケト酸が蓄積する。\n特徴：尿が甘い（メープルシロップ様）臭い。\n発育障害・知的障害・神経麻痺。", image:"images/sl6_bcaa.webp", imageAlt:"分枝アミノ酸の代謝経路（図12-7）" },
  { id:"l6-12", src:"第6回 アミノ酸代謝・尿素回路", field:"疾患", backImageOnly:true, term:"ホモシスチン尿症の原因と症状は？（メチオニン代謝）", desc:"メチオニン代謝でシスタチオニンβ-シンターゼが欠損。\nホモシステインが蓄積する。\n症状：知能障害、高身長・四肢指伸長、骨粗鬆症、水晶体偏位（視力低下）、血栓症。\n※メチオニン→SAM（メチル基供与体）→ホモシステインの下流。", image:"images/sl6_methionine.webp", imageAlt:"メチオニンの代謝経路（SAM・ホモシステイン）（図12-11）" },
  { id:"l6-13", src:"第6回 アミノ酸代謝・尿素回路", field:"生理活性アミン", backImageOnly:true, term:"アミノ酸の脱炭酸で作られる生理活性アミンは？共通の補酵素は？", desc:"脱炭酸酵素がCO₂を外し、第一級アミン（生理活性アミン）に。補酵素はPLP（ビタミンB₆）。\nチロシン→ドパミン→ノルアドレナリン→アドレナリン（カテコールアミン）。\nグルタミン酸→GABA（抑制性伝達物質）。\nトリプトファン→セロトニン。\nヒスチジン→ヒスタミン。", image:"images/sl6_decarboxylation.webp", imageAlt:"アミノ酸の脱炭酸反応による生理活性アミンの合成（図8-10）" },
  { id:"l6-14", src:"第6回 アミノ酸代謝・尿素回路", field:"アミノ酸の役割", backImageOnly:true, term:"チロシン・トリプトファンから作られる重要物質は？", desc:"チロシン→ドパ→ドパミン→ノルアドレナリン→アドレナリン（伝達物質・ホルモン）。\nチロシン→メラニン（色素）・甲状腺ホルモン。\nトリプトファン→セロトニン→メラトニン（ホルモン）。\nトリプトファン→NAD⁺（補酵素、ナイアシン）。", image:"images/sl6_aa_fates.webp", imageAlt:"各種アミノ酸の体内変化（チロシン・トリプトファン系）（図8）" },
  { id:"l6-15", src:"第6回 アミノ酸代謝・尿素回路", field:"アミノ酸の役割", backImageOnly:true, term:"グリシン・アルギニン・グルタミン酸などから作られる物質は？", desc:"グリシン＋スクシニルCoA→5-アミノレブリン酸→ヘム→ヘモグロビン（酸素運搬）。\nアルギニン＋グリシン→クレアチン→クレアチンリン酸。\nグルタミン酸＋システイン＋グリシン→グルタチオン（抗酸化）。\nシステイン→タウリン→胆汁酸。\nセリン→コリン（リン脂質成分）。", image:"images/sl6_aa_fates.webp", imageAlt:"各種アミノ酸の体内変化（ヘム・クレアチン・その他）（図8）" },
  { id:"l6-16", src:"第6回 アミノ酸代謝・尿素回路", field:"アミノ酸の役割・臨床", backImageOnly:true, term:"クレアチン・クレアチニンの作られ方と、クレアチニンが腎機能検査に使える理由は？", desc:"アルギニン＋グリシン→（腎）グアニジノ酢酸→（肝、SAMがメチル基供与）クレアチン。\n筋肉でクレアチンキナーゼによりクレアチンリン酸（エネルギー貯蔵）に。\n一定割合が非酵素的に分解→クレアチニン→尿へ。\n産生量が筋肉量に比例し一定→腎機能（糸球体濾過）の指標。", image:"images/sl6_creatine.webp", imageAlt:"クレアチンおよびクレアチニンの生合成（図12-13）" },
  { id:"l6-17", src:"第6回 アミノ酸代謝・尿素回路", field:"アミノ酸の合成", backImageOnly:true, term:"非必須アミノ酸はどんな中間体から合成される？", desc:"α-ケトグルタル酸→グルタミン酸→グルタミン・プロリン・アルギニン。\nピルビン酸→アラニン（ALT）。\nオキサロ酢酸→アスパラギン酸（AST）→アスパラギン。\n3-ホスホグリセリン酸→セリン→グリシン・システイン。\nフェニルアラニン→チロシン。\nアミノ基はアミノ基転移（補酵素PLP）で供給。", image:"images/sl6_nonessential.webp", imageAlt:"非必須アミノ酸の合成（図10）" },
  { id:"l6-18", src:"第6回 アミノ酸代謝・尿素回路", field:"電子伝達系", backImageOnly:true, term:"電子伝達系と酸化的リン酸化とは？ATPはどう作る？（化学浸透圧説）", desc:"NADH・FADH₂の電子を複合体I〜IVが受け渡し、最後にO₂→水にする。\nこのとき複合体I・III・IVがH⁺を膜間腔へ汲み出す。\n→内膜を隔てたH⁺の濃度勾配ができる。\n複合体V（ATP合成酵素）がH⁺を通しながらADP→ATP（化学浸透圧説）。", image:"images/sl6_etc.webp", imageAlt:"電子伝達系と酸化的リン酸化の概要（図4-13）" },
  { id:"l6-19", src:"第6回 アミノ酸代謝・尿素回路", field:"電子伝達系", backImageOnly:true, term:"電子伝達系の5つの複合体の名前と役割は？", desc:"複合体I：NADH脱水素酵素（NADH→Q、H⁺汲み出し）。\n複合体II：コハク酸脱水素酵素（FADH₂→Q、汲み出しなし）。\n複合体III：シトクロムc還元酵素。\n複合体IV：シトクロムc酸化酵素（電子をO₂→水）。\n複合体V：ATP合成酵素（ADP→ATP）。", image:"images/sl6_etc.webp", imageAlt:"電子伝達系の5つの複合体（図4-13）" },
  { id:"l6-20", src:"第6回 アミノ酸代謝・尿素回路", field:"電子伝達系", backImageOnly:true, term:"細胞質NADHはどう電子をミトコンドリアへ運ぶ？2つのシャトルのATP収支は？", desc:"NADHは内膜を通れないので、電子だけをシャトルで運ぶ。\nリンゴ酸-アスパラギン酸シャトル（肝・心・腎）→1 NADHで約2.5 ATP。\nグリセロール3-リン酸シャトル（骨格筋・脳）→FADH₂経由で約1.5 ATP。", image:"images/sl6_nadh_shuttle.webp", imageAlt:"NADHのミトコンドリア内膜への移動（シャトル）（図4-14）" },
  { id:"l6-21", src:"第6回 アミノ酸代謝・尿素回路", field:"電子伝達系・毒物", backImageOnly:true, term:"電子伝達系（酸化的リン酸化）を阻害する代表的な毒物と標的は？", desc:"複合体I：ロテノン、バルビツール酸。\n複合体II：マロン酸。\n複合体III：アンチマイシンA。\n複合体IV：シアン(CN⁻)・一酸化炭素(CO)・硫化水素（ヘムに結合）。\n複合体V：オリゴマイシン。\n※調節は複合体VがADPで活性化・ATPで抑制。", image:"images/sl6_etc_poisons.webp", imageAlt:"電子伝達系を標的とする毒物（表4-3）" },
  { id:"l6-22", src:"第6回 アミノ酸代謝・尿素回路", field:"栄養", backImageOnly:true, term:"必須・非必須・準必須アミノ酸の違いは？", desc:"必須（9種）＝合成できず食事から。メチオニン・フェニルアラニン・ヒスチジン・ロイシン・イソロイシン・リシン・トレオニン・トリプトファン・バリン。\n非必須（11種）＝体内で合成できる。\n準必須＝アルギニン・ヒスチジン（小児では不足しがち）。", image:"images/sl6_essential_table.webp", imageAlt:"栄養学的必須アミノ酸と非必須アミノ酸（表12-1）" },

  /* ================= 第7回（2026/5/27）酵素の機能と調節・ビタミン微量元素①（関根弘樹）=================
     ※「表＝問い／裏＝図＋短い答え」。答えは1行1ポイントで簡潔に（\n で改行表示）。
     ※図のないカード（可逆/不可逆・制御法まとめ）は image なしのテキストカード。 */
  { id:"l7-01", src:"第7回 酵素の機能と調節", field:"酵素とは", backImageOnly:true, term:"酵素とは何か？「基質特異性」とはどういう性質？", desc:"酵素＝特定の反応を助けるタンパク質の触媒。\n基質（S）＝酵素が変化させる相手の物質。\n酵素の活性部位が、特定の基質とだけ「鍵と鍵穴」のようにぴったり合う。\n→この選び分けが基質特異性。", image:"images/sl7_enzyme_lock.webp", imageAlt:"酵素反応（鍵と鍵穴・酵素-基質複合体）" },
  { id:"l7-02", src:"第7回 酵素の機能と調節", field:"酵素とは", backImageOnly:true, term:"酵素は反応を速める。どういう仕組みで速める？", desc:"反応が進むには「活性化エネルギー」の山を越える必要がある。\n酵素はこの山を低くする（E→E'）。\n→少ないエネルギーで反応でき、反応が速く進む。\n※酵素自身は反応前後で変化しない（触媒）。", image:"images/sl7_enzyme_energy.webp", imageAlt:"酵素反応のエネルギー変化（活性化エネルギー）" },
  { id:"l7-03", src:"第7回 酵素の機能と調節", field:"酵素とは", backImageOnly:true, term:"酵素の正体（実体）は何？例外はある？", desc:"酵素の実体はタンパク質。\n例外：リボザイム（触媒作用をもつRNA）。\nタンパク質なので、常温・常圧でも反応を進められる。\n例：ニトロゲナーゼは常温常圧で窒素固定（工業のハーバー・ボッシュ法は高温高圧が必要）。", image:"images/sl7_nitrogenase.webp", imageAlt:"ニトロゲナーゼとハーバー・ボッシュ法の条件比較" },
  { id:"l7-04", src:"第7回 酵素の機能と調節", field:"酵素反応の速度論", backImageOnly:true, term:"ミカエリス・メンテン式のVmaxとKmは、それぞれ何を表す？", desc:"V₀ = Vmax[S] /（Km＋[S]）\nVmax＝最大反応速度（基質で飽和したときの速さ）。\nKm（ミカエリス定数）＝反応速度がVmaxの半分になる基質濃度。\nグラフは基質濃度[S]に対して飽和する曲線になる。", image:"images/sl7_mm_curve.webp", imageAlt:"ミカエリス・メンテンの反応速度曲線" },
  { id:"l7-05", src:"第7回 酵素の機能と調節", field:"酵素反応の速度論", backImageOnly:true, term:"Kmが小さいと、酵素と基質の親和性は高い？低い？", desc:"Kmが小さい＝少ない基質で半分の速度に達する。\n→酵素と基質の親和性が高い。\nKmが大きい＝親和性が低い。\n（Kmは「速度が半分になる基質濃度」。小さいほど基質をつかまえやすい）", image:"images/sl7_mm_curve.webp", imageAlt:"ミカエリス・メンテンの反応速度曲線とKm" },
  { id:"l7-06", src:"第7回 酵素の機能と調節", field:"酵素反応の速度論", backImageOnly:true, term:"ラインウィーバー・バークプロットとは？何が読み取れる？", desc:"MM式の両辺の逆数をとって直線にしたグラフ（1/V₀ 対 1/[S]）。\n傾き＝Km/Vmax。\n縦軸切片＝1/Vmax、横軸切片＝−1/Km。\n→直線なのでVmax・Kmを求めやすく、阻害の型も見分けられる。", image:"images/sl7_lb_plot.webp", imageAlt:"ラインウィーバー・バークプロット" },
  { id:"l7-07", src:"第7回 酵素の機能と調節", field:"酵素の阻害", term:"酵素阻害の「可逆阻害」と「不可逆阻害」の違いは？", desc:"可逆阻害：阻害剤が酵素から外れられる。多くの薬剤。\n　→競合・非競合・不競合の3型。\n不可逆阻害：阻害剤が酵素に強固に結合し外れない。毒物が多い。\n　例：有機リン（アセチルコリンエステラーゼを阻害）、重金属（水銀・鉛→SH基に結合）。" },
  { id:"l7-08", src:"第7回 酵素の機能と調節", field:"酵素の阻害", backImageOnly:true, term:"競合的阻害の特徴は？（阻害剤が結合する場所と、Km・Vmaxの変化）", desc:"基質に似た構造の阻害剤が、活性部位を基質と奪い合う。\n基質を増やせば打ち勝てる（反応は十分進む）。\nKm：大きくなる／Vmax：変わらない。\n例：マロン酸によるコハク酸脱水素酵素の阻害。", image:"images/sl7_competitive.webp", imageAlt:"競合阻害の模式図と反応速度の変化" },
  { id:"l7-09", src:"第7回 酵素の機能と調節", field:"酵素の阻害", backImageOnly:true, term:"非競合的阻害の特徴は？（Km・Vmaxの変化）", desc:"阻害剤が活性部位以外に結合し、酵素の形を変えて働きを下げる。\n基質を増やしても回復しない。\nKm：変わらない／Vmax：小さくなる。\n例：水銀によるウレアーゼの阻害。", image:"images/sl7_noncompetitive.webp", imageAlt:"非競合阻害の模式図と反応速度の変化" },
  { id:"l7-10", src:"第7回 酵素の機能と調節", field:"酵素の阻害", backImageOnly:true, term:"不競合的阻害の特徴は？（Km・Vmaxの変化）", desc:"阻害剤は「酵素-基質複合体（ES）」にだけ結合して働きを下げる。\nKm：小さくなる／Vmax：小さくなる。\nKm/Vmaxの比は変わらない（プロットが平行移動）。", image:"images/sl7_uncompetitive.webp", imageAlt:"不競合阻害の模式図と反応速度の変化" },
  { id:"l7-11", src:"第7回 酵素の機能と調節", field:"補因子・補酵素", backImageOnly:true, term:"「補因子」とは？大きく何に分けられる？", desc:"補因子＝酵素が働くために基質以外に必要な助っ人。\n①金属イオン（Mg²⁺, Zn²⁺, Fe²⁺, Cu²⁺ など）。\n②補酵素（有機化合物）。\n補酵素はさらに、緩く結合する補基質と、強く結合する補欠分子族に分けられる。", image:"images/sl7_cofactor_table.webp", imageAlt:"補因子（金属イオン・補酵素）の分類" },
  { id:"l7-12", src:"第7回 酵素の機能と調節", field:"補因子・補酵素", backImageOnly:true, term:"主な補酵素と、その材料になるビタミンの対応は？", desc:"NAD＝ナイアシン、FAD＝ビタミンB₂、TPP＝ビタミンB₁、\nPLP＝ビタミンB₆、CoA＝パントテン酸、THF＝葉酸、\n補酵素B₁₂＝ビタミンB₁₂、ビオチン＝ビオチン。\n→多くの水溶性ビタミンが補酵素の材料になる。", image:"images/sl7_coenzyme_table.webp", imageAlt:"主な補酵素の一覧と由来するビタミン" },
  { id:"l7-13", src:"第7回 酵素の機能と調節", field:"補因子・補酵素", backImageOnly:true, term:"アポ酵素・ホロ酵素・補欠分子族とは？", desc:"アポ酵素＝補因子がついておらず働けない酵素。\nホロ酵素＝補因子が結合して働ける状態の酵素。\n補欠分子族＝酵素に強く（共有結合などで）結合した補因子。\n例：ヘム（シトクロムやヘモグロビンに含まれる）。", image:"images/sl7_apo_holo.webp", imageAlt:"アポ酵素とホロ酵素" },
  { id:"l7-14", src:"第7回 酵素の機能と調節", field:"酵素の活性制御", term:"酵素の活性（働き）はどんな方法で調節される？（5つ）", desc:"①温度・pH（例：リソソームは酸性で働く酵素）。\n②酵素の量（遺伝子発現で増減）。\n③化学修飾（リン酸化などの翻訳後修飾）。\n④アロステリック制御（活性部位以外に結合して促進/抑制）。\n⑤プロセッシング（前駆体を切って活性化）。" },
  { id:"l7-15", src:"第7回 酵素の機能と調節", field:"酵素の活性制御", backImageOnly:true, term:"酵素にはそれぞれ最適pHがある。リソソームで働く酵素の例は？", desc:"酵素は最適pHで最もよく働く。\nリソソーム＝細胞内の分解（異化）を担う小器官で、内部はpH約5の酸性。\nこの酸性で働くのがカテプシン（タンパク質分解酵素）。\n→場所に応じて最適pHの酵素が使い分けられている。", image:"images/sl7_lysosome.webp", imageAlt:"リソソームによる細胞内分解（エンドサイトーシス・オートファジー）" },
  { id:"l7-16", src:"第7回 酵素の機能と調節", field:"酵素の活性制御", backImageOnly:true, term:"アロステリック制御とは？", desc:"活性化因子や阻害剤が、活性部位とは別の場所（アロステリック部位）に結合する。\n酵素の形が変わり、活性が上がったり（促進）下がったり（抑制）する。\n反応曲線はS字状で、少しの濃度変化に敏感。\n→代謝の速さを素早く切り替えられる。", image:"images/sl7_allosteric.webp", imageAlt:"アロステリック制御（促進・抑制）と反応速度曲線" },
  { id:"l7-17", src:"第7回 酵素の機能と調節", field:"酵素の活性制御", backImageOnly:true, term:"酵素の「プロセッシング（限定分解）」による活性化とは？", desc:"不活性な前駆体の一部が切断されて、初めて働く酵素になる仕組み。\n例：トリプシノーゲン（膵臓で作られ、小腸で切断されトリプシンに）。\n例：アポトーシスのカスパーゼ。\n※急性膵炎＝膵臓内でトリプシンが誤って活性化し、自分の膵臓を消化してしまう。", image:"images/sl7_processing.webp", imageAlt:"プロセッシング（前駆体の限定分解による活性化）" },
  { id:"l7-18", src:"第7回 酵素の機能と調節", field:"酵素の分類", backImageOnly:true, term:"酵素は反応の形式で7群（EC1〜7）に分類される。それぞれは？", desc:"EC1 酸化還元酵素（オキシドレダクターゼ）\nEC2 転移酵素（トランスフェラーゼ）\nEC3 加水分解酵素（ヒドロラーゼ／消化酵素など）\nEC4 脱離酵素（リアーゼ）\nEC5 異性化酵素（イソメラーゼ）\nEC6 合成酵素（リガーゼ／ATPを使う）\nEC7 輸送酵素（トランスロカーゼ）", image:"images/sl7_ec_classes.webp", imageAlt:"反応形式による酵素の分類（EC1〜EC7）" },
  { id:"l7-19", src:"第7回 酵素の機能と調節", field:"酵素と疾患", backImageOnly:true, term:"「逸脱酵素」とは？臓器障害の検査にどう使う？", desc:"逸脱酵素＝臓器が障害されると、細胞内の酵素が血中に漏れ出てくるもの。\n血中の酵素活性を測ると、どの臓器が傷んでいるか分かる（バイオマーカー）。\n例：AST・ALT・γ-GT→肝機能障害で上昇。\n例：LDH（乳酸脱水素酵素）。", image:"images/sl7_ldh_isozyme.webp", imageAlt:"LDHアイソザイムと発現組織・疾患" },
  { id:"l7-20", src:"第7回 酵素の機能と調節", field:"酵素と疾患", backImageOnly:true, term:"LDH（乳酸脱水素酵素）のアイソザイムが臓器の特定に役立つのはなぜ？", desc:"LDHはH型とM型サブユニット4個の組み合わせで、LDH1〜5の5種類（アイソザイム）になる。\n組織ごとに多い型が違う。\nLDH1が高い＝心筋・赤血球（心筋梗塞・溶血）。\nLDH5が高い＝肝臓・骨格筋（肝炎・筋障害）。\n→どのLDHが上がるかで障害臓器を推定できる。", image:"images/sl7_ldh_isozyme.webp", imageAlt:"LDHアイソザイム（H型・M型の組み合わせ）と組織分布" },
  /* ================= 第8回（2026/5/28）酵素の機能と調節・ビタミン微量元素②（関根弘樹）=================
     ※ビタミン各論・補酵素・欠乏症＋最先端研究。表＝問い／裏＝図＋短い答え（\n で改行）。第7回（酵素）の続き。 */
  { id:"l8-01", src:"第8回 ビタミン・補酵素", field:"ビタミン総論", backImageOnly:true, term:"ビタミンとは？5大栄養素と分類は？", desc:"ビタミン＝微量で代謝に必須だが体内で合成できない有機化合物の総称（外から摂取）。\nビタミン同士に化学構造の共通点はない。\n3大栄養素（糖質・タンパク質・脂質）＋ビタミン＋無機質＝5大栄養素。\n脂溶性（A・D・E・K）と水溶性（B群・C）に分けられる。", image:"images/sl8_vitamin_types.webp", imageAlt:"ビタミンの分類（脂溶性・水溶性）" },
  { id:"l8-02", src:"第8回 ビタミン・補酵素", field:"ビタミン総論", backImageOnly:true, term:"脂溶性ビタミンと水溶性ビタミンの性質の違いは？", desc:"脂溶性（A・D・E・K）：脂肪とともに小腸で吸収、肝臓・脂肪組織に貯蔵できる→摂りすぎで過剰症。\n水溶性（B群・C）：貯蔵できず余剰は尿へ排泄→不足で欠乏症になりやすい。\nビタミンB群＝補酵素の前駆体、ビタミンC＝抗酸化作用。", image:"images/sl8_solubility.webp", imageAlt:"脂溶性（貯蔵可・過剰症）と水溶性（貯蔵不可・欠乏症）" },
  { id:"l8-03", src:"第8回 ビタミン・補酵素", field:"水溶性ビタミン(B群)", backImageOnly:true, term:"ビタミンB1（チアミン）→ 補酵素と欠乏症は？", desc:"ビタミンB1 → チアミンピロリン酸（TPP）。\n糖質代謝の補酵素。\n欠乏症＝脚気（末梢神経障害・心不全）。\nエネルギー需要の高い神経・心臓が障害される。白米を主食とする地域で有名。", image:"images/sl8_b1_tpp.webp", imageAlt:"チアミンピロリン酸（TPP）の構造" },
  { id:"l8-04", src:"第8回 ビタミン・補酵素", field:"水溶性ビタミン(B群)", backImageOnly:true, term:"ビタミンB2（リボフラビン）→ 補酵素と働きは？", desc:"ビタミンB2 → FAD（フラビンアデニンジヌクレオチド）。\n酸化還元反応を行うフラビン酵素の補酵素。\n単独欠乏では大きな病気にならないが口内炎などをきたす。\n（他のビタミン欠乏を伴うことが多い）", image:"images/sl8_b2_fad.webp", imageAlt:"FAD（フラビンアデニンジヌクレオチド）の構造" },
  { id:"l8-05", src:"第8回 ビタミン・補酵素", field:"水溶性ビタミン(B群)", backImageOnly:true, term:"ナイアシン（ビタミンB3）→ 補酵素と欠乏症は？", desc:"ナイアシン → NAD・NADP。\n脱水素酵素の補酵素で、酸化還元反応の水素の授受を担う。\n欠乏症＝ペラグラ（皮膚炎・下痢・認知症の3徴）。\nトウモロコシを主食とする地域の貧困層に多い。", image:"images/sl8_niacin_nad.webp", imageAlt:"NAD⁺とNADP⁺の構造" },
  { id:"l8-06", src:"第8回 ビタミン・補酵素", field:"水溶性ビタミン(B群)", backImageOnly:true, term:"ビタミンB6（ピリドキシン）→ 補酵素と働き・欠乏症は？", desc:"ビタミンB6 → ピリドキサールリン酸（PLP）。\nアミノ基転移・アミノ酸の脱炭酸の補酵素。\nセロトニン・ドパミン・GABAなど神経伝達物質の産生に必須→欠乏でてんかん様症状。\n肝機能検査のAST・ALTもPLP依存性酵素。", image:"images/sl8_b6_plp.webp", imageAlt:"ピリドキサールリン酸（PLP）の構造" },
  { id:"l8-07", src:"第8回 ビタミン・補酵素", field:"水溶性ビタミン(B群)", backImageOnly:true, term:"パントテン酸 → 補酵素と働きは？", desc:"パントテン酸 → 補酵素A（CoA）。\nアシル基（R-CO-）転移の補酵素。末端のSH基にアシル基が結合しアシルCoAになる。\nアセチルCoA＝β酸化やアミノ酸分解で生じ、TCA回路の入口。\nアセチル化（翻訳後修飾）の供与体にもなる。", image:"images/sl8_pantothenate_coa.webp", imageAlt:"補酵素A（CoA）とパントテン酸の構造" },
  { id:"l8-08", src:"第8回 ビタミン・補酵素", field:"水溶性ビタミン(B群)", backImageOnly:true, term:"ビオチン → 働きと、欠乏が起こる特殊な状況は？", desc:"ビオチン＝炭酸固定化（カルボキシ化）酵素の補欠分子。酵素のリシン残基に共有結合。\n糖新生・脂肪酸合成/分解・アミノ酸分解に関与。\n生卵白の大量摂取→卵白のアビジンがビオチンと強く結合し相対的に欠乏する。", image:"images/sl8_biotin.webp", imageAlt:"ビオチンの構造と酵素との結合部位" },
  { id:"l8-09", src:"第8回 ビタミン・補酵素", field:"水溶性ビタミン(B群)", backImageOnly:true, term:"葉酸 → 補酵素と、妊娠での重要性は？", desc:"葉酸 → テトラヒドロ葉酸（THF）。\n一炭素単位の転移・メチオニン合成の補酵素で、細胞増殖・成長に必要。\n欠乏＝巨赤芽球性貧血。\n妊婦で欠乏しやすく、胎児の神経管閉鎖障害（二分脊椎）の原因→妊娠前からの葉酸摂取で予防。", image:"images/sl8_folate_thf.webp", imageAlt:"テトラヒドロ葉酸（THF）と葉酸の構造" },
  { id:"l8-10", src:"第8回 ビタミン・補酵素", field:"水溶性ビタミン(B群)", backImageOnly:true, term:"ビタミンB12 → 補酵素と欠乏症は？", desc:"ビタミンB12 → 補酵素B12。\n核酸合成・メチル基転移・アミノ酸代謝の補欠分子。\n欠乏症＝悪性貧血（巨赤芽球性貧血）。\n分子内にコバルト（Co）を含む。", image:"images/sl8_b12.webp", imageAlt:"補酵素B12（コバラミン）の構造" },
  { id:"l8-11", src:"第8回 ビタミン・補酵素", field:"水溶性ビタミン(C)", backImageOnly:true, term:"ビタミンC（アスコルビン酸）の働きと欠乏症は？", desc:"強い還元力で抗酸化作用・水酸化反応に関与。\n特にコラーゲンのプロリン/リシン残基の水酸化に必要。\n欠乏症＝壊血病（コラーゲン不良で血管がもろくなり易出血、骨・筋の脆弱化）。\nヒト・サル・モルモットは体内で合成できない。", image:"images/sl8_scurvy_collagen.webp", imageAlt:"コラーゲン線維の生成（水酸化を受けて三重らせんを形成）" },
  { id:"l8-12", src:"第8回 ビタミン・補酵素", field:"水溶性ビタミン(C)", backImageOnly:true, term:"なぜビタミンC欠乏で壊血病になるのか？（機序）", desc:"コラーゲンはプロリン残基が水酸化されて三重らせん構造を保つ。\n水酸化はプロリン水酸化酵素（O₂・Fe²⁺依存）が触媒。\nビタミンCはこの酵素のFeを還元して活性を保つ。\n→C不足で水酸化が進まず、コラーゲン生成不良→血管が脆弱になる。", image:"images/sl8_scurvy_prolyl.webp", imageAlt:"プロリン水酸化酵素反応とビタミンC（アスコルビン酸）" },
  { id:"l8-13", src:"第8回 ビタミン・補酵素", field:"補酵素", backImageOnly:true, term:"ビタミン由来以外の主な補酵素とその働きは？", desc:"補酵素Q（ユビキノン）：電子伝達系の電子伝達体（チロシンから合成）。\nSAM（S-アデノシルメチオニン）：メチル基の供与体。\nUDP-グルコース：グルコース供与体（グリコーゲン・多糖合成の中間体）。\nα-リポ酸：アシル基転移の補欠分子。（ATPはリン酸基の供与体）", image:"images/sl8_other_coenzymes.webp", imageAlt:"補酵素Q・α-リポ酸・UDPグルコース・SAMの構造" },
  { id:"l8-14", src:"第8回 ビタミン・補酵素", field:"脂溶性ビタミン", backImageOnly:true, term:"ビタミンA（レチノイド）の働きと欠乏症は？", desc:"小腸で吸収→肝臓に貯蔵→RBP（レチノール結合タンパク質）で各組織へ。\n視覚（ロドプシン成分）・細胞分化/遺伝子発現・成長・免疫・上皮保護に働く（核内受容体のリガンド）。\n欠乏症＝夜盲症。\nレチノール（アルコール型）／レチナール（アルデヒド型）／レチノイン酸（酸型）。", image:"images/sl8_vitamin_a.webp", imageAlt:"レチノイド（ビタミンA）とβカロテンの構造・分類" },
  { id:"l8-15", src:"第8回 ビタミン・補酵素", field:"脂溶性ビタミン", backImageOnly:true, term:"ビタミンDはどこで活性化され、何を調節する？", desc:"D2（植物）とD3（動物・皮膚で紫外線から生成）が主。\n肝臓で25位、腎臓で1位が水酸化され活性型1,25-(OH)₂-Dになる。\nカルシウム調節ホルモンとして：小腸でCa・P吸収↑、骨からCa放出、腎でCa再吸収↑。\n核内受容体（VDR）のリガンド。", image:"images/sl8_vitamin_d.webp", imageAlt:"ビタミンD2/D3の生成と肝・腎での活性化" },
  { id:"l8-16", src:"第8回 ビタミン・補酵素", field:"脂溶性ビタミン", backImageOnly:true, term:"ビタミンE（トコフェロール）の働きは？", desc:"代表はα-トコフェロール（生理活性が最も強い）。\n抗酸化作用：細胞膜の多価不飽和脂肪酸の酸化を防ぎ、フリーラジカルを捕捉。\nビタミンAやDの分解も防ぐ。\n抗不妊因子として発見された。", image:"images/sl8_vitamin_e.webp", imageAlt:"ビタミンE（α-トコフェロール）の構造" },
  { id:"l8-17", src:"第8回 ビタミン・補酵素", field:"脂溶性ビタミン", backImageOnly:true, term:"ビタミンKの働きと、拮抗薬は？", desc:"血液凝固に関与（Koagulation が名の由来）。\nグルタミン酸残基のカルボキシル化（Gla化）の補酵素→プロトロンビンなど凝固因子や骨のオステオカルシンを活性化。\nK1（緑黄色野菜）／K2（納豆・微生物）／K3（合成・最強）。\n拮抗薬ワルファリン＝血栓症の治療薬。", image:"images/sl8_vitamin_k.webp", imageAlt:"ビタミンK1の構造" },
  { id:"l8-18", src:"第8回 ビタミン・補酵素", field:"脂溶性ビタミン", backImageOnly:true, term:"脂溶性ビタミン（A・D）はどうやって遺伝子発現を変える？（核内受容体）", desc:"核内受容体は通常、細胞質でHSP90と結合して不活性。\nリガンド（ビタミンD3・A、エストロゲンなど）が結合するとHSP90が外れ核内へ移行。\n転写因子として結合配列につき、遺伝子発現を活性化する。\n→A・Dは「ホルモン様作用」をもつ（VDR・ERなど）。", image:"images/sl8_nuclear_receptor.webp", imageAlt:"細胞内における核内受容体（通常状態とリガンド状態）" },
  { id:"l8-19", src:"第8回 ビタミン・補酵素", field:"最先端研究", backImageOnly:true, term:"NADが老化・寿命研究で注目される理由は？（最先端）", desc:"NADは寿命制御因子SIRT1（サーチュイン）の活性に必須。\nSIRT1は各臓器で脂肪酸酸化・糖脂質代謝・神経保護・インスリン分泌などを調節。\nNADの前駆体NMN/ナイアシンの補充が抗老化として研究されている。", image:"images/sl8_nad_sirt1.webp", imageAlt:"The NAD World（NAD-SIRT1による全身の代謝制御）" },
  { id:"l8-20", src:"第8回 ビタミン・補酵素", field:"最先端研究", backImageOnly:true, term:"2019年ノーベル賞「細胞の酸素感知」とコラーゲンの水酸化反応の共通点は？", desc:"低酸素応答の中心HIF-1αは、正常酸素下でプロリンが水酸化される。\nこの水酸化はコラーゲンと同じFe(II)・2-OG依存性水酸化酵素の反応。\n水酸化されたHIF-1αはVHLに認識され分解される（低酸素では分解されず安定化）。\nFeやビタミンC（還元）が関わる点も共通。", image:"images/sl8_hif.webp", imageAlt:"HIF-1αのプロリル水酸化とVHLによる分解（2019年ノーベル賞）" },
  { id:"l8-21", src:"第8回 ビタミン・補酵素", field:"最先端研究", backImageOnly:true, term:"ビタミンEやKと「フェロトーシス」の関係は？（最先端）", desc:"フェロトーシス＝鉄依存性の脂質過酸化による細胞死（虚血再灌流障害などに関与）。\nビタミンE・Kは脂質の過酸化を抑えることでフェロトーシスを防ぐ。\nGPX4やCoQ10も脂質過酸化を抑制する因子。", image:"images/sl8_ferroptosis.webp", imageAlt:"フェロトーシス（鉄依存性の脂質過酸化による細胞死）の経路" },

  /* ================= 第9回（2026/6/3）糖質の構造と糖質代謝➊（張旭紅）＝糖質の構造・分類、消化吸収、解糖系とその調節 ================= */
  { id:"l9-01", src:"第9回 糖質の構造・解糖系", field:"糖質総論", backImageOnly:true, term:"糖質（炭水化物）の定義は？", desc:"アルデヒド基（-CHO）またはケトン基（>C=O）を1つもち、\n2つ以上のヒドロキシ基（-OH）をもつ、炭素数3以上の化合物。\nアルデヒド基をもつ＝アルドース（例：グルコース）。\nケトン基をもつ＝ケトース（例：フルクトース）。\n化学式は Cₙ(H₂O)ₙ ＝「炭水化物」。", image:"images/sl9_definition.webp", imageAlt:"グルコース（アルドース）とフルクトース（ケトース）の構造" },
  { id:"l9-02", src:"第9回 糖質の構造・解糖系", field:"糖質総論", backImageOnly:true, term:"糖質は結合した単糖の数でどう分類される？", desc:"単糖類：それ以上加水分解されない最小単位（グルコース・フルクトース・ガラクトース）。\nオリゴ糖類：単糖2〜10個（二糖＝マルトース・スクロース・ラクトースなど）。\n多糖類：単糖が10個超。\n単純多糖（ホモ：デンプン・セルロース・グリコーゲン）と複合多糖（ヘテロ：プロテオグリカン・糖タンパク質・糖脂質）。", image:"images/sl9_classification.webp", imageAlt:"糖質の分類（単糖・オリゴ糖・多糖）" },
  { id:"l9-03", src:"第9回 糖質の構造・解糖系", field:"糖質総論", backImageOnly:true, term:"単糖はどんな基準で分類・命名される？", desc:"官能基：アルドース（-CHO）／ケトース（>C=O）。\n炭素数：三炭糖（トリオース）〜六炭糖（ヘキソース）。\n立体配置：D型/L型、α/βアノマー。\n環状構造：フラノース（五員環）／ピラノース（六員環）。\n誘導体：アミノ糖・アルドン酸/ウロン酸・糖アルコール。", image:"images/sl9_monosaccharide_table.webp", imageAlt:"単糖の分類基準と名称の一覧表" },
  { id:"l9-04", src:"第9回 糖質の構造・解糖系", field:"単糖", backImageOnly:true, term:"単糖の立体異性体（鏡像異性体・エピマー）とは？", desc:"不斉炭素の立体配置が異なる化合物。\n鏡像異性体（D/L）：カルボニル基から最も遠い不斉炭素のOHが右＝D型、左＝L型。生体の糖は主にD型。\nジアステレオマー：互いに鏡像でない立体異性体。\nエピマー：不斉炭素のOH配置が1個だけ違うもの。", image:"images/sl9_stereoisomer.webp", imageAlt:"D-/L-グリセルアルデヒドの鏡像異性体と不斉炭素原子" },
  { id:"l9-05", src:"第9回 糖質の構造・解糖系", field:"単糖", backImageOnly:true, term:"単糖はなぜ環状構造をとる？六員環・五員環の呼び名は？", desc:"単糖の多くは直鎖ではなくヘミアセタール/ヘミケタール結合で環状構造をとり、生理的条件で安定。\n六員環＝ピラノース。\n五員環＝フラノース。\n（環状をとる割合は糖の種類やpHで変化する。）", image:"images/sl9_ring.webp", imageAlt:"グルコース・フルクトースの開環型とハース式（ピラノース・フラノース）" },
  { id:"l9-06", src:"第9回 糖質の構造・解糖系", field:"単糖", backImageOnly:true, term:"α・βアノマー（アノマー炭素）とは？", desc:"環状化でアルデヒド/ケトン基由来の炭素（アノマー炭素）が新たな不斉炭素になる。\nそのOHの向きで α型（環の下）と β型（環の上）に分かれる。\n両者は開環型を介して相互変換する（変旋光）。\nグリコシド結合を作るとアノマー配置は固定される。", image:"images/sl9_anomer.webp", imageAlt:"α-/β-D-グルコピラノースと直鎖状D-グルコースの相互変換" },
  { id:"l9-07", src:"第9回 糖質の構造・解糖系", field:"単糖", backImageOnly:true, term:"糖はどんな反応で誘導体に変換される？", desc:"酸化：グルクロン酸・グルコノラクトン。\n還元：ソルビトール（糖アルコール）。\nエステル化：グルコース6-リン酸。\nエピマー化/異性化：マンノース・フルクトース。\nグリコシド形成：メチルグルコシドなど。", image:"images/sl9_derivatives.webp", imageAlt:"グルコースの酸化・還元・置換・異性化による相互変換" },
  { id:"l9-08", src:"第9回 糖質の構造・解糖系", field:"単糖", backImageOnly:true, term:"デオキシ糖とは？代表例と役割は？", desc:"-OH基が-Hに置換した糖。\n2-デオキシリボース＝DNAの構成成分（原料）。\nフコース（6-デオキシ-L-ガラクトース）＝ABO血液型のH抗原などに使われる。", image:"images/sl9_deoxy.webp", imageAlt:"2-デオキシリボースとα-L-フコース（デオキシ糖）" },
  { id:"l9-09", src:"第9回 糖質の構造・解糖系", field:"単糖", backImageOnly:true, term:"アミノ糖とは？その役割は？", desc:"OH基の1つがアミノ基（-NH₂）に置き換わった糖。\n多くはアミノ基がアセチル化されている（N-アセチルグルコサミン・N-アセチルガラクトサミン）。\n細胞表面の糖鎖・多糖・糖タンパク質を構成し、細胞認識や組織保護に働く。", image:"images/sl9_aminosugar.webp", imageAlt:"グルコサミン・ガラクトサミンとN-アセチル体" },
  { id:"l9-10", src:"第9回 糖質の構造・解糖系", field:"単糖", backImageOnly:true, term:"主な単糖（グルコース・フルクトース・ガラクトース・マンノース・リボース）の役割は？", desc:"グルコース：血糖＝基本的なエネルギー源。デンプン・セルロースの骨格。\nフルクトース：ショ糖の成分、エネルギー源。\nガラクトース：乳糖の成分、糖脂質の原料。\nマンノース：糖タンパク質・糖脂質の成分。\nリボース：ヌクレオチド＝核酸の成分。", image:"images/sl9_monosaccharide_roles.webp", imageAlt:"主な単糖（グルコース・フルクトース・ガラクトース・マンノース・リボース）の構造" },
  { id:"l9-11", src:"第9回 糖質の構造・解糖系", field:"二糖", backImageOnly:true, term:"グリコシド結合とは？", desc:"糖のアノマー炭素のOHと、相手のOHまたはアミノ基（-NH₂）が結合し、水（H₂O）が取れる（脱水縮合）。\n逆反応は加水分解（水が必要）。\n単糖はグリコシド結合で二糖・オリゴ糖・多糖を形成する。", image:"images/sl9_glycosidic.webp", imageAlt:"2つの単糖のグリコシド結合（縮合と加水分解）" },
  { id:"l9-12", src:"第9回 糖質の構造・解糖系", field:"二糖", backImageOnly:true, term:"代表的な二糖（マルトース・ラクトース・スクロース）の構成単糖は？", desc:"マルトース（麦芽糖）＝グルコース＋グルコース（α1,4）。\nラクトース（乳糖）＝ガラクトース＋グルコース（β1,4）。\nスクロース（ショ糖）＝グルコース＋フルクトース（α1,β2）。\n結合は「アノマー炭素のOH配置（α/β）」と「結合する炭素番号」で決まる。", image:"images/sl9_disaccharide.webp", imageAlt:"マルトース・ラクトース・スクロースの構造とグリコシド結合" },
  { id:"l9-13", src:"第9回 糖質の構造・解糖系", field:"二糖", backImageOnly:true, term:"還元糖・還元性末端とは？", desc:"アルデヒド基/ケトン基をもち、他の物質を還元する糖。\nアノマー炭素の酸素が他と結合していなければ還元糖。\n全ての単糖、および一部の二糖（マルトース・ラクトース）は還元糖。\nアノマー炭素が遊離している末端＝還元性末端。", image:"images/sl9_reducing.webp", imageAlt:"マルトースの還元性末端・非還元性末端とアノマー炭素" },
  { id:"l9-14", src:"第9回 糖質の構造・解糖系", field:"二糖", backImageOnly:true, term:"二糖の分解酵素は？乳糖不耐症はなぜ起こる？", desc:"マルトース→マルターゼ、イソマルトース→イソマルターゼ、ラクトース→ラクターゼ、スクロース→スクラーゼ。\n腸で吸収されるのは単糖のみ＝二糖は分解されないと吸収されない。\n乳糖不耐症：ラクターゼの欠損/低下で乳糖を分解できず、大腸で細菌が発酵→下痢・腹部膨満。", image:"images/sl9_lactose.webp", imageAlt:"二糖の分類・分解酵素とラクターゼ欠損（乳糖不耐症）" },
  { id:"l9-15", src:"第9回 糖質の構造・解糖系", field:"多糖", backImageOnly:true, term:"多糖はどう分類される？（ホモ/ヘテロ・直鎖/分枝）", desc:"ホモ多糖：同一種類の単糖から。直鎖＝アミロース・セルロース・キチン、分枝＝アミロペクチン・グリコーゲン・デキストリン。\nヘテロ多糖：異なる種類の単糖から。直鎖＝プロテオグリカン・グリコサミノグリカン、分枝＝糖タンパク質/糖脂質の糖鎖。", image:"images/sl9_polysaccharide.webp", imageAlt:"多糖の分類（ホモ/ヘテロ×直鎖/分枝）" },
  { id:"l9-16", src:"第9回 糖質の構造・解糖系", field:"多糖", backImageOnly:true, term:"デンプン（アミロース/アミロペクチン）とグリコーゲンの構造の違いは？", desc:"アミロース：グルコースがα1,4結合で直鎖状に連なる。\nアミロペクチン：α1,4の主鎖に24〜30残基ごとにα1,6の枝分かれ。\nグリコーゲン：動物のエネルギー貯蔵。α1,4とα1,6で連なり、アミロペクチンより鎖が短く枝分かれが多い。\n分解酵素＝アミラーゼ・マルターゼ・イソマルターゼ。", image:"images/sl9_starch.webp", imageAlt:"アミロース・アミロペクチン・グリコーゲンの構造" },
  { id:"l9-17", src:"第9回 糖質の構造・解糖系", field:"多糖", backImageOnly:true, term:"セルロースをヒトが消化できないのはなぜ？", desc:"植物の細胞壁を構成、自然界に最も多い多糖（紙・木綿の主成分）。\nグルコースがβ1,4結合＝ヒトはこれを分解する酵素（セルラーゼ）をもたない→消化吸収されない（食物繊維）。\n草食動物は消化管の共生細菌のセルラーゼに依存している。", image:"images/sl9_cellulose.webp", imageAlt:"セルロースのβ-1,4グリコシド結合と草食動物" },
  { id:"l9-18", src:"第9回 糖質の構造・解糖系", field:"多糖", backImageOnly:true, term:"グリコサミノグリカン（GAG／ムコ多糖）の特徴は？", desc:"「ウロン酸＋アミノ糖」の二糖の繰り返し（直鎖）。\n多くは硫酸基が付加している（ヒアルロン酸は例外）。\n代表＝ヒアルロン酸・コンドロイチン。\n強く負に帯電し、高い粘性・弾性・保水性をもつ（水溶液が粘稠＝ムコ多糖）。", image:"images/sl9_gag.webp", imageAlt:"グリコサミノグリカン（ヒアルロン酸・コンドロイチン）の繰り返し二糖単位" },
  { id:"l9-19", src:"第9回 糖質の構造・解糖系", field:"複合糖質", backImageOnly:true, term:"複合糖質（プロテオグリカン・糖タンパク質・糖脂質）の違いは？", desc:"プロテオグリカン：コアタンパク質＋グリコサミノグリカン（糖鎖が主・タンパク質が従）。\n糖タンパク質：糖鎖＋タンパク質（タンパク質が主・糖が従）。\n糖脂質：糖鎖＋脂質。\nいずれも細胞膜表面などに存在する。", image:"images/sl9_glycoconjugate.webp", imageAlt:"細胞膜表面のプロテオグリカン・糖タンパク質・糖脂質" },
  { id:"l9-20", src:"第9回 糖質の構造・解糖系", field:"複合糖質", backImageOnly:true, term:"プロテオグリカンの構造と、高い保水性の理由は？", desc:"ボトルブラシ構造。\nコアタンパク質＝ブラシの「芯」、グリコサミノグリカン（糖鎖）＝「毛」。\n硫酸基による強い負電荷で水分子を強く引き寄せる→極めて高い保水性。\n軟骨などの細胞外マトリックスの主成分（アグレカン）。", image:"images/sl9_proteoglycan.webp", imageAlt:"プロテオグリカン（アグレカン集合体）のボトルブラシ構造" },
  { id:"l9-21", src:"第9回 糖質の構造・解糖系", field:"複合糖質", backImageOnly:true, term:"糖タンパク質のN結合型・O結合型の違いは？", desc:"糖鎖はプロテオグリカンより短く、枝分かれが多い。\nN結合型：糖鎖がアスパラギン（Asn）の窒素原子に結合（多くの膜/分泌タンパク質）。\nO結合型：糖鎖がセリン/スレオニン（Ser/Thr）の酸素原子に結合（ムチン・血液型物質）。", image:"images/sl9_glycoprotein.webp", imageAlt:"N結合型・O結合型糖タンパク質の糖鎖結合様式" },
  { id:"l9-22", src:"第9回 糖質の構造・解糖系", field:"複合糖質", backImageOnly:true, term:"ABO式血液型は何で決まる？", desc:"赤血球表面の糖脂質の糖鎖構造で決まる。\nO型：共通の基本糖鎖（H抗原）のみ。\nA型：H抗原にN-アセチルガラクトサミンが付加。\nB型：H抗原にガラクトースが付加。\nAB型：A型とB型の両方の糖鎖をもつ。", image:"images/sl9_abo.webp", imageAlt:"ABO式血液型（赤血球表面の糖鎖の違い）" },
  { id:"l9-23", src:"第9回 糖質の構造・解糖系", field:"消化・吸収", backImageOnly:true, term:"デンプンはどこで、何の酵素により消化される？", desc:"口腔：唾液のα-アミラーゼでデキストリンに分解（胃の低pHで作用停止）。\n小腸：膵臓のα-アミラーゼでデキストリン→マルトースに。\n小腸粘膜上皮の膜結合酵素マルターゼがマルトース→グルコースに分解。\nグルコースは吸収され、門脈を通って肝臓へ。", image:"images/sl9_digestion.webp", imageAlt:"デンプンの消化（唾液・膵アミラーゼ→マルターゼ→グルコース）" },
  { id:"l9-24", src:"第9回 糖質の構造・解糖系", field:"消化・吸収", backImageOnly:true, term:"消化で生じた単糖（グルコース・ガラクトース・フルクトース）はどう吸収される？", desc:"単糖の吸収には特異的な輸送体が必要。\nグルコース・ガラクトース：管腔側からSGLT（Na⁺共輸送）で取り込む。\nフルクトース：GLUT（GLUT5）で取り込む。\n血管側へはGLUT（GLUT2）で出て、門脈→肝臓→全身へ。", image:"images/sl9_absorption.webp", imageAlt:"小腸上皮での単糖吸収（SGLT・GLUT）" },
  { id:"l9-25", src:"第9回 糖質の構造・解糖系", field:"グルコース輸送", backImageOnly:true, term:"細胞へのグルコース取り込みを担う2種の輸送体は？", desc:"GLUT（グルコーストランスポーター）：濃度勾配に従う促進拡散型（ユニポート）。細胞内外の濃度が等しくなる方向に運ぶ。\nSGLT（Na⁺依存性グルコース共輸送体）：細胞外の高いNa⁺濃度を利用し、グルコースとNa⁺を同時に細胞内へ（シンポート・実質的に能動輸送）。", image:"images/sl9_glut_sglt.webp", imageAlt:"GLUT（促進拡散）とSGLT（Na⁺共輸送）" },
  { id:"l9-26", src:"第9回 糖質の構造・解糖系", field:"グルコース輸送", backImageOnly:true, term:"GLUT1〜5の主な分布と特徴は？", desc:"GLUT-1：多くの細胞・赤血球・脳（Glc高親和性）。\nGLUT-2：肝・腎・小腸・膵β細胞（低親和性、血糖に応じ双方向輸送）。\nGLUT-3：神経細胞（高親和性）。\nGLUT-4：筋肉・脂肪細胞（インスリンで細胞膜へ移動＝糖を集める）。\nGLUT-5：小腸上皮（フルクトースを輸送）。", image:"images/sl9_glut_types.webp", imageAlt:"GLUT1〜5の組織分布と親和性" },
  { id:"l9-27", src:"第9回 糖質の構造・解糖系", field:"解糖系", backImageOnly:true, term:"解糖系とは？その4つの特徴は？", desc:"細胞質でグルコースをピルビン酸に変換する経路。\n①身体のほぼすべての細胞で起こる。\n②細胞質（細胞質ゾル）で行われる。\n③嫌気的反応で酸素を必要としない。\n④反応は速いがエネルギー産生効率は低い（正味2ATPのみ）。", image:"images/sl9_glycolysis_features.webp", imageAlt:"解糖系の特徴（細胞質・嫌気的・速いが低効率）" },
  { id:"l9-28", src:"第9回 糖質の構造・解糖系", field:"解糖系", backImageOnly:true, term:"解糖系10段階の全体収支は？（投資相・生成相）", desc:"エネルギー投資相（反応①〜⑤）：2ATPを消費して六炭糖を2つの三炭糖（GAP）に開裂。\nエネルギー生成相（反応⑥〜⑩）：4ATPと2NADHを産生。\n正味＝グルコース1分子→2ピルビン酸＋2ATP＋2NADH。", image:"images/sl9_glycolysis_overview.webp", imageAlt:"解糖系の投資相・生成相とATP/NADH収支" },
  { id:"l9-29", src:"第9回 糖質の構造・解糖系", field:"解糖系", backImageOnly:true, term:"解糖・投資相（反応①〜⑤）の流れは？", desc:"①ヘキソキナーゼ：グルコース→G6P（ATP消費・不可逆）。\n②PGI：G6P→F6P（アルドース→ケトースへ異性化）。\n③PFK1：F6P→フルクトース1,6-ビスリン酸（ATP消費・不可逆）。\n④アルドラーゼ：六炭糖→三炭糖2つ（GAP＋DHAP）に開裂。\n⑤トリオースリン酸イソメラーゼ：DHAP⇌GAP。", image:"images/sl9_investment.webp", imageAlt:"解糖投資相（グルコース→G6P→F6P→FBP→GAP/DHAP）" },
  { id:"l9-30", src:"第9回 糖質の構造・解糖系", field:"解糖系", backImageOnly:true, term:"①ヘキソキナーゼの反応と意義は？", desc:"グルコース＋ATP→グルコース6-リン酸（G6P）＋ADP。\n律速段階・不可逆。\nリン酸化でG6Pになると負電荷で細胞膜を通れなくなり、取り込んだグルコースを細胞内にとどめられる。\n肝ではグルコキナーゼ（HK Ⅳ）が担う。", image:"images/sl9_hexokinase.webp", imageAlt:"ヘキソキナーゼによるグルコースのリン酸化（G6P生成）" },
  { id:"l9-31", src:"第9回 糖質の構造・解糖系", field:"解糖系", backImageOnly:true, term:"③ホスホフルクトキナーゼ（PFK1）の反応と重要性は？", desc:"フルクトース6-リン酸＋ATP→フルクトース1,6-ビスリン酸＋ADP。\n生理的条件では不可逆＝解糖系で最も重要な律速段階。\n抑制：ATP・クエン酸。\n亢進：AMP・フルクトース2,6-ビスリン酸。", image:"images/sl9_pfk1.webp", imageAlt:"PFK1によるF6P→フルクトース1,6-ビスリン酸" },
  { id:"l9-32", src:"第9回 糖質の構造・解糖系", field:"解糖系", backImageOnly:true, term:"解糖・生成相（反応⑥〜⑩）でATP・NADHはどこで作られる？", desc:"⑥GAPDH：GAP→1,3-ビスホスホグリセリン酸＋NADH（最初の高エネルギー化合物）。\n⑦PGK：1,3-BPG→3-PG＋ATP（基質レベルのリン酸化）。\n⑧PGM→⑨エノラーゼ：PEP（高エネルギー）を生成。\n⑩PK：PEP→ピルビン酸＋ATP（不可逆・基質レベルのリン酸化）。", image:"images/sl9_payoff.webp", imageAlt:"解糖生成相（GAP→ピルビン酸、NADH・ATPの産生）" },
  { id:"l9-33", src:"第9回 糖質の構造・解糖系", field:"解糖系", backImageOnly:true, term:"基質レベルのリン酸化とは？酸化的リン酸化との違いは？", desc:"基質レベルのリン酸化：高エネルギー化合物のリン酸基を酵素が直接ADPに移してATPを作る（解糖系・TCA回路）。\n酸化的リン酸化：ミトコンドリア電子伝達系でATPを作る。\n高エネルギー化合物＝PEP・1,3-BPG・クレアチンリン酸・ATPなど。低エネルギー＝G6P・F6Pなど。", image:"images/sl9_substrate_phos.webp", imageAlt:"各種リン酸化合物の加水分解自由エネルギー（高エネルギー/低エネルギー）" },
  { id:"l9-34", src:"第9回 糖質の構造・解糖系", field:"解糖系の調節", backImageOnly:true, term:"解糖系で調節を受ける3つの不可逆酵素と、その活性化・阻害物質は？", desc:"不可逆＝①ヘキソキナーゼ・③PFK・⑩ピルビン酸キナーゼ。\nヘキソキナーゼ：G6P・ATPで阻害。\nPFK：フルクトース2,6-ビスリン酸・AMPで活性化、クエン酸・ATPで阻害。\nピルビン酸キナーゼ：フルクトース1,6-ビスリン酸・AMPで活性化、アセチルCoA・ATPで阻害。", image:"images/sl9_regulation_table.webp", imageAlt:"解糖系3酵素の活性化物質・阻害物質の一覧" },
  { id:"l9-35", src:"第9回 糖質の構造・解糖系", field:"解糖系の調節", backImageOnly:true, term:"PFK1はフルクトース2,6-ビスリン酸でどう調節される？", desc:"摂食時：PFK2（脱リン酸化状態）がF6P→F2,6BPを作り、F2,6BPがPFK1を活性化（解糖促進）。\n空腹時：PFK2（PKAでリン酸化）がF2,6BPを分解し、PFK1は不活性化。\nAMPでも活性化（嫌気的な筋で重要）、ATP・クエン酸で阻害。", image:"images/sl9_pfk1_reg.webp", imageAlt:"フルクトース2,6-ビスリン酸によるPFK1の調節（摂食時/空腹時）" },
  { id:"l9-36", src:"第9回 糖質の構造・解糖系", field:"解糖系の調節", backImageOnly:true, term:"ピルビン酸キナーゼ（PK）はどう調節される？", desc:"アロステリック調節：フルクトース1,6-ビスリン酸で活性化（フィードフォワード促進）、ATP・アラニンで阻害。\nホルモン調節：インスリンが脱リン酸化して活性化（促進）、グルカゴンがPKA経由でリン酸化して不活性化（抑制）。", image:"images/sl9_pk_reg.webp", imageAlt:"ピルビン酸キナーゼのアロステリック調節とホルモン調節" },
  { id:"l9-37", src:"第9回 糖質の構造・解糖系", field:"ピルビン酸・組織代謝", backImageOnly:true, term:"解糖で生じたピルビン酸の主な4つの行方は？", desc:"アセチルCoA（酸化的脱炭酸・好気的）：ミトコンドリアTCA回路でATP産生。\n乳酸（還元・嫌気的/赤血球）：NAD⁺を再生し解糖を継続、肝で糖新生に。\nオキサロ酢酸（カルボキシ化・空腹時）：糖新生の出発物質、TCA中間体の補充。\nアラニン（アミノ基転移・筋）：窒素を安全に肝へ運ぶ。", image:"images/sl9_pyruvate_fate.webp", imageAlt:"ピルビン酸の行方（アセチルCoA・乳酸・オキサロ酢酸・アラニン）" },
  { id:"l9-38", src:"第9回 糖質の構造・解糖系", field:"ピルビン酸・組織代謝", backImageOnly:true, term:"なぜ嫌気的条件でピルビン酸は乳酸に変換される？", desc:"乳酸脱水素酵素（LDH）がピルビン酸＋NADH→乳酸＋NAD⁺を触媒。\n嫌気下ではNADHを酸化してNAD⁺を再生しないと解糖系が止まる→再生のため乳酸を作る。\n赤血球（ミトコンドリアなし）・酸素不足の筋・腫瘍細胞では常に乳酸を作り血中へ放出する。", image:"images/sl9_lactate.webp", imageAlt:"ピルビン酸→乳酸（LDH）とNAD⁺の再生" },
  { id:"l9-39", src:"第9回 糖質の構造・解糖系", field:"ピルビン酸・組織代謝", backImageOnly:true, term:"脳（神経細胞）のエネルギー源は？絶食時はどうなる？", desc:"神経細胞のエネルギー源は主にグルコース（絶えず必要）。\nアミノ酸からはグルコースを取り込めない（脳へは供給されない経路）。\n長期の飢餓時にはケトン体（脂質代謝で生成）も利用できるようになる。\n産生したATPはNa⁺/K⁺-ATPaseなどに使われる。", image:"images/sl9_brain.webp", imageAlt:"脳のエネルギー代謝（グルコース主・飢餓時ケトン体）" },
  { id:"l9-40", src:"第9回 糖質の構造・解糖系", field:"ピルビン酸・組織代謝", backImageOnly:true, term:"白筋（速筋）と赤筋（遅筋）のエネルギー代謝の違いは？", desc:"白筋（速筋）：短時間に急に働く筋で、ミトコンドリアが少ない→酸素を使わずグルコースを乳酸まで分解する嫌気的代謝が中心。\n赤筋（遅筋）：ゆっくり長く収縮する筋で、ミトコンドリアが多い→酸素を使う好気的代謝（酸化的リン酸化）が中心。", image:"images/sl9_muscle.webp", imageAlt:"遅筋（赤筋・好気的）と速筋（白筋・嫌気的）" },
  { id:"l9-41", src:"第9回 糖質の構造・解糖系", field:"ピルビン酸・組織代謝", backImageOnly:true, term:"ワールブルク効果とは？", desc:"正常な分化細胞：酸素があれば酸化的リン酸化、無ければ嫌気的解糖。\n腫瘍細胞：酸素が十分あっても解糖でピルビン酸→乳酸を多く作る（好気的解糖）。\nこれをワールブルク効果という（Otto Warburg、1931年ノーベル賞）。\nがんのPET検査（糖の取り込みを見る）の原理にもつながる。", image:"images/sl9_warburg.webp", imageAlt:"ワールブルク効果（腫瘍細胞の好気的解糖）" },

  /* ================= 第10回（2026/6/4）糖質の代謝❷（張旭紅）＝クエン酸回路・電子伝達系／グリコーゲン代謝／糖新生／ペントースリン酸経路 ================= */
  { id:"l10-01", src:"第10回 糖質の代謝❷", field:"クエン酸回路", backImageOnly:true, term:"クエン酸回路（TCA回路）とは？その特徴は？", desc:"解糖系で生じたピルビン酸由来のアセチルCoAを酸化する、主要なエネルギー産生経路。\n①ミトコンドリア内で好気的条件下に進行する。\n②NADHやFADH₂を産生し、ATP産生につながる。\n③糖質・脂質・アミノ酸の代謝が合流する。\n別名：TCA回路・クレブス回路。", image:"images/sl10_tca_intro.webp", imageAlt:"クエン酸回路（TCA回路）の特徴" },
  { id:"l10-02", src:"第10回 糖質の代謝❷", field:"クエン酸回路", backImageOnly:true, term:"ピルビン酸はどこで、どうやってアセチルCoAになる？", desc:"ピルビン酸は外膜チャンネルと内膜のトランスロカーゼでミトコンドリアのマトリックスへ運ばれる。\nピルビン酸脱水素酵素複合体（PDH）が酸化的脱炭酸でアセチルCoAに変換（CO₂とNADHを生じる）。\n促進：NAD⁺・CoA／抑制：NADH・アセチルCoA。\n補酵素にTPP・α-リポ酸・FADが関与。", image:"images/sl10_pyruvate_acetylcoa.webp", imageAlt:"ピルビン酸→アセチルCoAの酸化的脱炭酸（PDH複合体）" },
  { id:"l10-03", src:"第10回 糖質の代謝❷", field:"クエン酸回路", backImageOnly:true, term:"アセチルCoAの高エネルギー結合とCoAの由来は？", desc:"アセチル基のカルボニル炭素が、CoAのチオール基（-SH）にチオエステル結合で結合。\nこのチオエステル結合が高エネルギー結合＝反応の駆動力になる。\n補酵素A（CoA）はパントテン酸（ビタミン）を含む分子。", image:"images/sl10_acetylcoa.webp", imageAlt:"補酵素A（CoA-SH）の構造とチオール基" },
  { id:"l10-04", src:"第10回 糖質の代謝❷", field:"クエン酸回路", backImageOnly:true, term:"ピルビン酸脱水素酵素複合体（PDH）の構成と補酵素は？", desc:"3種類の酵素（E1・E2・E3）と5種類の補酵素が結合した巨大複合体。\n補酵素：TPP（B₁）・α-リポ酸・CoA（パントテン酸）・FAD（B₂）・NAD⁺（ナイアシン）。\n反応中間体を離さず効率よく次へ受け渡す。\nビタミンB₁欠乏＝脚気（末梢神経障害・心不全）。", image:"images/sl10_pdh_complex.webp", imageAlt:"PDH複合体の3酵素（E1/E2/E3）と5補酵素" },
  { id:"l10-05", src:"第10回 糖質の代謝❷", field:"クエン酸回路", backImageOnly:true, term:"PDH複合体はどう調節される？", desc:"エネルギーが必要な時：Ca²⁺・インスリンでPDHホスファターゼがPDHを脱リン酸化＝活性化（アセチルCoA産生を促進）。\nエネルギーが十分な時：ATP・アセチルCoA・NADHの増加でPDHキナーゼがPDHをリン酸化＝不活性化。\n（PDH＝E1）", image:"images/sl10_pdh_regulation.webp", imageAlt:"PDHの活性化（脱リン酸化）と不活性化（リン酸化）" },
  { id:"l10-06", src:"第10回 糖質の代謝❷", field:"クエン酸回路", backImageOnly:true, term:"クエン酸回路の8段階（主な酵素）は？", desc:"①クエン酸シンターゼ（アセチルCoA＋オキサロ酢酸→クエン酸）\n②アコニターゼ→③イソクエン酸デヒドロゲナーゼ（NADH＋CO₂）\n④α-ケトグルタル酸デヒドロゲナーゼ（NADH＋CO₂）\n⑤スクシニルCoAシンテターゼ（GTP）\n⑥コハク酸デヒドロゲナーゼ（FADH₂）→⑦フマラーゼ→⑧リンゴ酸デヒドロゲナーゼ（NADH）", image:"images/sl10_tca_cycle.webp", imageAlt:"クエン酸回路の8段階と中間体" },
  { id:"l10-07", src:"第10回 糖質の代謝❷", field:"クエン酸回路", backImageOnly:true, term:"クエン酸回路1回転（アセチルCoA1個）の生成物は？", desc:"アセチルCoA1分子を消費し、オキサロ酢酸を再生する。\n生成：3NADH＋1FADH₂＋1GTP＋2CO₂。\n基質レベルのリン酸化でGTPが1つできる。\nNADH・FADH₂は電子伝達系に渡ってATP産生に使われる。", image:"images/sl10_tca_products.webp", imageAlt:"クエン酸回路の生成物（3NADH・FADH₂・GTP・2CO₂）" },
  { id:"l10-08", src:"第10回 糖質の代謝❷", field:"電子伝達系", backImageOnly:true, term:"電子伝達系と酸化的リン酸化の3ステップは？", desc:"電子伝達（酸化）とATP合成（リン酸化）が共役する反応（ミトコンドリア内膜）。\n①酸化：複合体Ⅰ〜Ⅳが電子を順に伝達し、最終的に酸素へ渡す。\n②プロトン勾配：生じたエネルギーでH⁺を膜間腔へ汲み出す。\n③リン酸化：H⁺の勾配（プロトン駆動力）でATP合成酵素がATPを作る。", image:"images/sl10_etc.webp", imageAlt:"電子伝達系（複合体Ⅰ〜Ⅴ）と酸化的リン酸化" },
  { id:"l10-09", src:"第10回 糖質の代謝❷", field:"電子伝達系", backImageOnly:true, term:"グルコース1分子の完全酸化で得られるATPは？", desc:"1NADH→2.5ATP、1FADH₂→1.5ATP。\n解糖：2NADH＋2ATP／PDH反応：2NADH／TCA：6NADH＋2FADH₂＋2GTP。\n合計 10NADH（25）＋2FADH₂（3）＋4（2ATP＋2GTP）＝約32ATP。\n（骨格筋では細胞質NADHの持ち込み方でやや少なくなる）", image:"images/sl10_atp_yield.webp", imageAlt:"グルコース完全酸化のエネルギー収支（約32ATP）" },
  { id:"l10-10", src:"第10回 糖質の代謝❷", field:"グリコーゲン代謝", backImageOnly:true, term:"グリコーゲンの構造と、肝・筋での役割の違いは？", desc:"多数のグルコースが枝分かれしてつながった高分子（α1,4主鎖＋α1,6分枝）。\n主に肝臓と筋肉（骨格筋）に蓄える。\n肝グリコーゲン：全身の血糖値を保つ予備タンク。\n筋グリコーゲン：筋肉自身の収縮（運動）エネルギーとしてのみ使う。", image:"images/sl10_glycogen_structure.webp", imageAlt:"グリコーゲンの枝分かれ構造（α1,4・α1,6結合）" },
  { id:"l10-11", src:"第10回 糖質の代謝❷", field:"グリコーゲン代謝", backImageOnly:true, term:"肝グリコーゲンと筋グリコーゲンの量と変動の違いは？", desc:"合成・貯蔵は食後の高血糖時に肝・筋で行われる。\n肝（約150g）：空腹時に分解して血糖として全身へ供給→食間変動が大きい。\n筋（約300g）：自身の運動で消費し血糖にはならない→食間変動が小さい。", image:"images/sl10_glycogen_balance.webp", imageAlt:"肝・筋のグリコーゲン貯蔵量と血糖への供給" },
  { id:"l10-12", src:"第10回 糖質の代謝❷", field:"グリコーゲン代謝", backImageOnly:true, term:"グリコーゲン合成の流れと基質・調節酵素は？", desc:"①グルコース→G6P→G1P。\n②G1P＋UTP→UDP-グルコース（活性型グルコース）。\n③グリコーゲンシンターゼ（調節酵素）がα1,4結合で鎖を伸長。\n④分枝酵素がα1,6の枝を作る（開始点はコアタンパク質グリコゲニン）。\n食後にインスリンで促進。", image:"images/sl10_glycogen_synthesis.webp", imageAlt:"グリコーゲン合成（UDP-グルコース・シンターゼ・分枝酵素）" },
  { id:"l10-13", src:"第10回 糖質の代謝❷", field:"グリコーゲン代謝", backImageOnly:true, term:"グリコーゲン分解の主な2段階と調節は？", desc:"①グリコーゲンホスホリラーゼ（調節酵素）が非還元末端からα1,4を加リン酸分解し、グルコース1-リン酸（G1P）を生成。枝の手前4残基で止まり限界デキストリンに。\n②脱分枝酵素：糖鎖転移＋α1,6の加水分解で枝を外す（一部は遊離グルコース）。\n空腹時はグルカゴン、運動時はアドレナリンで促進。", image:"images/sl10_glycogen_degradation.webp", imageAlt:"グリコーゲン分解（ホスホリラーゼ・脱分枝酵素）" },
  { id:"l10-14", src:"第10回 糖質の代謝❷", field:"グリコーゲン代謝", backImageOnly:true, term:"筋グリコーゲンが血糖にならないのはなぜ？", desc:"分解で生じたG1PはホスホグルコムターゼでG6Pになる。\nG6Pをグルコースにするにはグルコース6-ホスファターゼ（Glc-6-Pase、小胞体）が必要。\n肝臓：Glc-6-Paseを持つ→グルコースを血中へ放出し血糖を維持できる。\n筋肉：Glc-6-Paseを欠く→G6Pは自身の解糖系（エネルギー産生）へ回る。", image:"images/sl10_g6pase.webp", imageAlt:"肝はGlc-6-Paseを持ち血糖維持、筋は欠く" },
  { id:"l10-15", src:"第10回 糖質の代謝❷", field:"グリコーゲン代謝", backImageOnly:true, term:"グリコーゲン代謝はホルモンでどう調節される？", desc:"インスリン（食後）：プロテインホスファターゼを介して合成酵素を活性化・ホスホリラーゼを抑制→合成（同化）。\nグルカゴン/アドレナリン（空腹・運動）：cAMP→PKAで合成酵素を抑制・ホスホリラーゼを活性化→分解（異化）。\n合成酵素とホスホリラーゼは互いに逆向きに制御される。", image:"images/sl10_glycogen_regulation.webp", imageAlt:"グリコーゲン代謝のホルモン調節（インスリン↔グルカゴン）" },
  { id:"l10-16", src:"第10回 糖質の代謝❷", field:"グリコーゲン代謝", backImageOnly:true, term:"糖原病とは？代表的な型は？", desc:"グリコーゲン代謝や解糖系の酵素の遺伝子異常で、肝や筋にグリコーゲンが蓄積する病気。\nⅠ型 フォンギールケ病：グルコース6-ホスファターゼ欠損（肝・腎）。\nⅡ型 ポンペ病：α1,4-グルコシダーゼ（リソソーム）欠損（全器官）。\nⅢ型 コリ病：脱分枝酵素。Ⅴ型 マッカードル病：筋ホスホリラーゼ。", image:"images/sl10_glycogen_storage_disease.webp", imageAlt:"糖原病の型・欠損酵素・蓄積臓器の一覧" },
  { id:"l10-17", src:"第10回 糖質の代謝❷", field:"糖新生", backImageOnly:true, term:"糖新生とは？どこで、何を材料に行われる？", desc:"空腹時などに糖質以外の物質からグルコースを合成し、血糖を維持して脳・筋へ供給する経路。\n場所：肝臓（約90%）と腎臓（約10%）。\n主な基質：乳酸・グリセロール・ピルビン酸・糖原性アミノ酸。\nエネルギーを消費する同化反応。", image:"images/sl10_gng_overview.webp", imageAlt:"糖新生の概略（場所・基質・エネルギー消費）" },
  { id:"l10-18", src:"第10回 糖質の代謝❷", field:"糖新生", backImageOnly:true, term:"糖新生が解糖系の不可逆3反応を迂回する4つの酵素は？", desc:"解糖系をほぼ逆行するが、不可逆な3反応を4つの固有酵素で迂回する。\nヘキソキナーゼの迂回：グルコース6-ホスファターゼ。\nPFK-1の迂回：フルクトース1,6-ビスホスファターゼ。\nピルビン酸キナーゼの迂回：ピルビン酸カルボキシラーゼ（ビオチン要）＋PEPCK。\n開始はミトコンドリア、終了は小胞体。", image:"images/sl10_gng_enzymes.webp", imageAlt:"糖新生固有の4酵素（Glc-6-Pase・F-1,6-BPase・PC・PEPCK）" },
  { id:"l10-19", src:"第10回 糖質の代謝❷", field:"糖新生", backImageOnly:true, term:"ピルビン酸2分子からグルコース1分子を作るのに必要なエネルギーは？", desc:"6個の高エネルギーリン酸結合（4ATP＋2GTP）と2NADHが必要。\n解糖系は2ATPを産生するだけなので、逆行にはずっと多くのエネルギーを消費する。\nエネルギーを使う同化反応。", image:"images/sl10_gng_energy.webp", imageAlt:"糖新生のエネルギー収支（4ATP＋2GTP＋2NADH消費）" },
  { id:"l10-20", src:"第10回 糖質の代謝❷", field:"糖新生", backImageOnly:true, term:"糖新生と解糖系はどう相反的に調節される？", desc:"フルクトース2,6-ビスリン酸（F2,6BP）：解糖促進・糖新生抑制。インスリンで増加、グルカゴンで減少。\nアセチルCoA：ピルビン酸カルボキシラーゼを活性化＝糖新生を始動。\nAMP/ATP（エネルギーチャージ）でも相反的に調節。\n→空腹時は糖新生、食後は解糖が優位。", image:"images/sl10_gng_regulation.webp", imageAlt:"糖新生と解糖系の相反的調節（F2,6BP・アセチルCoA）" },
  { id:"l10-21", src:"第10回 糖質の代謝❷", field:"糖新生", backImageOnly:true, term:"コリ回路とは？その意義は？", desc:"筋肉：グルコース→乳酸（嫌気的解糖）→血液へ。\n肝臓：血液から乳酸→糖新生でグルコース→血液へ戻す。\n意義：血糖の維持（乳酸の再利用）と、乳酸蓄積（アシドーシス）の防止。", image:"images/sl10_liver_muscle_cycles.webp", imageAlt:"コリ回路（筋の乳酸→肝の糖新生）とグルコース-アラニン回路" },
  { id:"l10-22", src:"第10回 糖質の代謝❷", field:"糖新生", backImageOnly:true, term:"グルコース-アラニン回路の役割は？", desc:"筋肉：ピルビン酸＋アミノ基→アラニン→血液へ。\n肝臓：血液からアラニン→グルコース＋尿素（解毒）。\n意義：骨格筋のアミノ酸代謝で生じた有毒なアンモニアを、安全にアラニンとして肝へ運び解毒する（窒素の輸送）。\nアミノ基転移酵素はALT。", image:"images/sl10_liver_muscle_cycles.webp", imageAlt:"グルコース-アラニン回路（窒素の肝への輸送）" },
  { id:"l10-23", src:"第10回 糖質の代謝❷", field:"糖新生", backImageOnly:true, term:"糖新生の材料になるアミノ酸・ならないものは？", desc:"糖原性アミノ酸：ピルビン酸やTCA中間体を経てオキサロ酢酸に変換され、糖新生に使える。\nロイシン（Leu）とリシン（Lys）は糖新生できない（ケト原性のみ）。\n脂質（脂肪酸）は原則、糖新生の原料にならない（グリセロールと奇数鎖脂肪酸の一部のみ可）。", image:"images/sl10_glucogenic_aa.webp", imageAlt:"糖原性アミノ酸のTCA回路への合流点（Lys・Leuは不可）" },
  { id:"l10-24", src:"第10回 糖質の代謝❷", field:"ペントースリン酸経路", backImageOnly:true, term:"ペントースリン酸経路の2つの意義は？", desc:"グルコース6-リン酸から分岐する経路（ATPは作らない）。\n①還元当量NADPHの供給：脂肪酸・ステロイド合成や抗酸化に使う。\n②五炭糖リボース（リボース5-リン酸）の供給：核酸（DNA・RNA）合成に必要。", image:"images/sl10_ppp_overview.webp", imageAlt:"ペントースリン酸経路の意義（NADPHとリボースの供給）" },
  { id:"l10-25", src:"第10回 糖質の代謝❷", field:"ペントースリン酸経路", backImageOnly:true, term:"ペントースリン酸経路の酸化的・非酸化的反応の違いは？", desc:"酸化的反応（不可逆）：G6PからCO₂を放出しつつNADPHを産生する。\n非酸化的反応（可逆）：生じた五炭糖を組み替え、リボースを供給したり過剰分を解糖系（F6P・GA3P）へ戻す。\n目的はATP産生ではなく、生体分子の材料供給。", image:"images/sl10_ppp_reactions.webp", imageAlt:"ペントースリン酸経路の酸化的反応（NADPH）と非酸化的反応" },
  { id:"l10-26", src:"第10回 糖質の代謝❷", field:"ペントースリン酸経路", backImageOnly:true, term:"NADPHの主な機能と、G6PD欠乏症とは？", desc:"①抗酸化：グルタチオンを還元し活性酸素（ROS）から細胞を守る。\n②脂肪酸・コレステロール・ステロイド合成の還元剤。\n③生体防御：好中球のNADPHオキシダーゼが活性酸素を作り殺菌。\n④薬物代謝（シトクロムP450）。\nG6PD欠乏症：NADPH産生障害で、薬剤や感染を契機に溶血（赤血球破壊）を起こす遺伝病。", image:"images/sl10_nadph.webp", imageAlt:"NADPHの機能とG6PD欠乏症（溶血）" },
  { id:"l10-27", src:"第10回 糖質の代謝❷", field:"ペントースリン酸経路", backImageOnly:true, term:"リボース5-リン酸（R5P）の主な役割は？", desc:"①核酸合成：活性型のPRPP（5-ホスホリボシル-1-二リン酸）を経て、プリン・ピリミジンヌクレオチドの材料になる。\n②高エネルギー化合物・補酵素（ATP・NAD(P)⁺・FAD・CoA）の骨格。\n③トランスケトラーゼ/トランスアルドラーゼで解糖系中間体（F6P・GA3P）と可逆的に連携する。", image:"images/sl10_r5p.webp", imageAlt:"リボース5-リン酸の役割（核酸・補酵素・解糖系連携）" },
  { id:"l10-28", src:"第10回 糖質の代謝❷", field:"その他の糖代謝", backImageOnly:true, term:"フルクトース・ガラクトース・マンノースはどう代謝に入る？", desc:"いずれもリン酸化・変換され、解糖系や糖代謝の中間体に合流する。\nフルクトース：フルクトース1-リン酸→（アルドラーゼB）→GA3P・DHAP。\nガラクトース：ガラクトース1-リン酸→UDP-ガラクトース→UDP-グルコース。\nマンノース：マンノース6-リン酸→フルクトース6-リン酸。", image:"images/sl10_other_sugars.webp", imageAlt:"フルクトース・ガラクトース・マンノースの代謝経路" },
  { id:"l10-29", src:"第10回 糖質の代謝❷", field:"その他の糖代謝", backImageOnly:true, term:"糖ヌクレオチドとは？その役割は？", desc:"単糖にヌクレオチド（UDP・GDP・CMPなど）が結合した化合物（例：UDP-グルコース）。\n役割：糖の相互変換、糖鎖（複合糖質）の合成、グルクロン酸抱合による解毒、活性型糖としての利用。\nグリコーゲン合成の基質UDP-グルコースもこの一種。", image:"images/sl10_sugar_nucleotide.webp", imageAlt:"糖ヌクレオチド（単糖＋UDP/GDP/CMP）と生理機能" },
  { id:"l10-30", src:"第10回 糖質の代謝❷", field:"その他の糖代謝", backImageOnly:true, term:"グルクロン酸経路の合成ルートと2大機能は？", desc:"ルート：グルコース6-リン酸→グルコース1-リン酸→UDP-グルコース→UDP-グルクロン酸（グルコースのC6を酸化）。\n①肝臓での解毒：グルクロン酸抱合（ビリルビンや薬物を水溶性にして排泄）。\n②細胞外マトリックス（糖鎖・プロテオグリカン）の材料。", image:"images/sl10_glucuronic.webp", imageAlt:"グルクロン酸経路（UDP-グルクロン酸の生成と機能）" }
];
